const EARTHQUAKE_QUERY_RE = /\b(active\s+)?earthquakes?\b|\bseismic\b|\bquake\b|\btremor\b/i;

function entityString(entity: UnifiedEntity, keys: string[], fallback = "") {
  for (const key of keys) {
    const value = entity.properties?.[key];
    if (typeof value === "string" && value.trim()) return value;
    if (typeof value === "number" && Number.isFinite(value)) return String(value);
  }
  return fallback;
}

function entityNumber(entity: UnifiedEntity, keys: string[]) {
  for (const key of keys) {
    const value = entity.properties?.[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string") {
      const parsed = Number(value);
      if (Number.isFinite(parsed)) return parsed;
    }
  }
  return undefined;
}

function entityLink(entity: UnifiedEntity) {
  return entityString(entity, ["sourceUrl", "link", "url"]);
}

function firstHoverValue(record: Record<string, any> | undefined, keys: string[], fallback = ""): string {
  if (!record) return fallback;
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "string" && value.trim()) return value.trim();
    if (typeof value === "number" && Number.isFinite(value)) return String(value);
  }
  return fallback;
}

function readLooseValue(entity: any, keys: string[]): unknown {
  const bags = [
    entity,
    entity?.properties,
    entity?.metadata,
    entity?.properties?.metadata,
    entity?.raw,
    entity?.feature?.properties,
  ];
  for (const bag of bags) {
    if (!bag || typeof bag !== "object") continue;
    for (const key of keys) {
      const value = bag[key];
      if (value == null || value === "") continue;
      if (typeof value === "number" && !Number.isFinite(value)) continue;
      return value;
    }
  }
  return undefined;
}

function formatMycaFactValue(value: unknown, suffix = ""): string {
  if (value == null || value === "") return "";
  if (typeof value === "number") return Number.isFinite(value) ? `${Math.round(value)}${suffix}` : "";
  if (typeof value === "boolean") return value ? "yes" : "no";
  if (Array.isArray(value)) return value.filter(Boolean).slice(0, 3).join(", ");
  if (value instanceof Date) return value.toLocaleString();
  if (typeof value === "object") return "";
  const text = String(value).trim();
  return text ? `${text}${suffix}` : "";
}

function formatMycaDateFact(value: unknown): string {
  const text = formatMycaFactValue(value);
  if (!text) return "";
  const date = new Date(text);
  if (!Number.isNaN(date.getTime())) {
    return date.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
  }
  return text;
}

function pushMycaFact(facts: MycaContextFact[], label: string, value: unknown, suffix = "") {
  const formatted = formatMycaFactValue(value, suffix);
  if (!formatted) return;
  const normalized = `${label}:${formatted}`.toLowerCase();
  if (facts.some((fact) => `${fact.label}:${fact.value}`.toLowerCase() === normalized)) return;
  facts.push({ label, value: formatted });
}

function buildHoverFacts(payload: MapAssetHoverPayload): MycaContextFact[] {
  const props = payload.properties || {};
  const facts: MycaContextFact[] = [];
  pushMycaFact(facts, "Type", props.type || props.sub_type || props.kind || payload.kind || payload.type);
  pushMycaFact(facts, "Operator", props.operator || props.op || props.owner || props.OWNER || props.provider);
  pushMycaFact(facts, "Status", props.status || props.source_status);
  const capacity = Number(props.capacity_mw ?? props.capacityMW);
  if (Number.isFinite(capacity) && capacity > 0) pushMycaFact(facts, "Capacity", capacity, " MW");
  const voltage = Number(props.voltage_kv ?? props.v ?? props.VOLTAGE);
  if (Number.isFinite(voltage) && voltage > 0) pushMycaFact(facts, "Voltage", voltage > 1000 ? Math.round(voltage / 1000) : voltage, " kV");
  pushMycaFact(facts, "Speed", props.speed ?? props.sog ?? props.velocity ?? props.groundSpeed, props.sog != null ? " kt" : "");
  pushMycaFact(facts, "Heading", props.heading ?? props.cog ?? props.course, " deg");
  pushMycaFact(facts, "Source", payload.source || props.source || props.src);
  return facts.slice(0, 6);
}

function buildSelectedMapWidgetContext(kind: string, detail: any): MycaSelectedMapContext | null {
  if (!detail || typeof detail !== "object") return null;
  const normalizedKind = kind.toLowerCase();
  const props = detail.properties || detail;
  const label = String(
    detail.label ||
    detail.name ||
    detail.title ||
    props.name ||
    props.title ||
    props.label ||
    normalizedKind,
  ).trim();
  const lat = Number(detail.lat ?? detail.latitude ?? props.lat ?? props.latitude);
  const lng = Number(detail.lng ?? detail.lon ?? detail.longitude ?? props.lng ?? props.lon ?? props.longitude);
  const id = detail.id ?? props.id ?? props.station_id ?? props.source_id ?? label;
  const payload: MapAssetHoverPayload = {
    type: kind,
    kind,
    id,
    name: label,
    label,
    detail: detail.detail || props.detail || props.description,
    lat: Number.isFinite(lat) ? lat : undefined,
    lng: Number.isFinite(lng) ? lng : undefined,
    source: detail.source || props.source || props.provider,
    properties: props,
    x: 0,
    y: 0,
  };
  const facts = buildHoverFacts(payload);
  pushMycaFact(facts, "Provider", props.provider || detail.provider || props.source);
  pushMycaFact(facts, "Camera", props.camera_id || props.station_id || props.id);
  pushMycaFact(facts, "Stream", props.stream_url || props.streamUrl || props.embed_url || props.media_url ? "available" : "");
  return {
    key: `${formatHoverKeyPart(kind, "asset")}:${formatHoverKeyPart(id, label)}`,
    kind,
    label: label || kind,
    detail: formatHoverDetail(payload) || props.description || props.provider || props.source,
    facts: facts.slice(0, 8),
    lat: Number.isFinite(lat) ? lat : undefined,
    lng: Number.isFinite(lng) ? lng : undefined,
    zoom: normalizedKind.includes("camera") ? 14 : 12,
  };
}

function formatHoverKeyPart(value: string | number | undefined, fallback: string): string {
  return String(value ?? fallback).trim().toLowerCase().replace(/\s+/g, "-").slice(0, 90) || fallback;
}

function formatHoverDetail(payload: MapAssetHoverPayload): string {
  if (payload.detail?.trim()) return payload.detail.trim();
  const props = payload.properties || {};
  const parts: string[] = [];
  const add = (label: string, value: unknown, suffix = "") => {
    if (value == null || value === "") return;
    if (typeof value === "number" && !Number.isFinite(value)) return;
    const text = String(value).trim();
    if (!text || parts.some((part) => part.toLowerCase() === `${label}: ${text}${suffix}`.toLowerCase())) return;
    parts.push(`${label}: ${text}${suffix}`);
  };
  add("Status", props.status || props.source_status);
  add("Operator", props.operator || props.op || props.owner || props.OWNER);
  add("Provider", props.provider);
  add("Type", props.type || props.sub_type || props.kind || props.radio || props.device_type);
  const capacity = Number(props.capacity_mw ?? props.capacityMW);
  if (Number.isFinite(capacity) && capacity > 0) add("Capacity", Math.round(capacity), " MW");
  const voltage = Number(props.voltage_kv ?? props.v ?? props.VOLTAGE);
  if (Number.isFinite(voltage) && voltage > 0) add("Voltage", voltage > 1000 ? Math.round(voltage / 1000) : Math.round(voltage), " kV");
  add("Source", payload.source || props.source || props.src);
  return parts.slice(0, 3).join(" / ");
}

function normalizeHoverPayload(payload: MapAssetHoverPayload): MapHoverContext | null {
  const props = payload.properties || {};
  const kind = String(payload.kind || payload.type || props.type || "asset").replace(/[_-]+/g, " ");
  const label =
    payload.label ||
    payload.name ||
    firstHoverValue(props, ["name", "n", "title", "label", "callsign", "station_id", "id"], kind);
  const rawLat = payload.lat ?? props.lat ?? props.latitude;
  const rawLng = payload.lng ?? props.lng ?? props.lon ?? props.longitude;
  const lat = Number(rawLat);
  const lng = Number(rawLng);
  const x = Number(payload.x ?? payload.screenX);
  const y = Number(payload.y ?? payload.screenY);
  const id = payload.id ?? props.id ?? props.plant_id ?? props.station_id ?? props.mmsi ?? props.imo;
  if (!label || !Number.isFinite(x) || !Number.isFinite(y)) return null;
  return {
    key: `${formatHoverKeyPart(kind, "asset")}:${formatHoverKeyPart(id, label)}`,
    kind,
    label,
    detail: formatHoverDetail(payload),
    facts: buildHoverFacts(payload),
    lat: Number.isFinite(lat) ? lat : undefined,
    lng: Number.isFinite(lng) ? lng : undefined,
    x,
    y,
    source: payload.source || firstHoverValue(props, ["source", "src", "provider"]),
  };
}

function hoverToneClass(kind: string) {
  const normalized = kind.toLowerCase();
  if (normalized.includes("camera")) return "border-sky-300/50 bg-sky-950/80 text-sky-100 shadow-sky-500/25";
  if (normalized.includes("plant") || normalized.includes("transmission") || normalized.includes("substation")) return "border-amber-300/50 bg-amber-950/80 text-amber-100 shadow-amber-500/25";
  if (normalized.includes("species") || normalized.includes("fung")) return "border-emerald-300/50 bg-emerald-950/80 text-emerald-100 shadow-emerald-500/25";
  if (normalized.includes("event") || normalized.includes("fire") || normalized.includes("earthquake")) return "border-orange-300/50 bg-orange-950/80 text-orange-100 shadow-orange-500/25";
  if (normalized.includes("aircraft") || normalized.includes("vessel") || normalized.includes("satellite")) return "border-cyan-300/50 bg-cyan-950/80 text-cyan-100 shadow-cyan-500/25";
  return "border-purple-300/50 bg-purple-950/80 text-purple-100 shadow-purple-500/25";
}

function MapAssetHoverPreview({ hover }: { hover: MapHoverContext | null }) {
  if (!hover || typeof window === "undefined") return null;
  const left = Math.max(12, Math.min(window.innerWidth - 286, hover.x + 16));
  const top = Math.max(12, Math.min(window.innerHeight - 132, hover.y + 16));
  const coordinates =
    hover.lat != null && hover.lng != null
      ? `${hover.lat.toFixed(4)}, ${hover.lng.toFixed(4)}`
      : null;

  return (
    <div
      data-testid="crep-hover-preview"
      className={cn(
        "pointer-events-none fixed z-[80] w-[270px] rounded-md border p-2 shadow-2xl backdrop-blur-md",
        hoverToneClass(hover.kind),
      )}
      style={{ left, top }}
    >
      <div className="mb-1 flex items-center justify-between gap-2">
        <span className="truncate text-[8px] font-bold uppercase tracking-wide opacity-80">{hover.kind}</span>
        {hover.source && <span className="shrink-0 text-[7px] uppercase opacity-60">{hover.source}</span>}
      </div>
      <div className="truncate text-[11px] font-bold text-white">{hover.label}</div>
      {hover.detail && <div className="mt-1 line-clamp-2 text-[9px] leading-snug text-white/80">{hover.detail}</div>}
      {coordinates && <div className="mt-1 font-mono text-[8px] text-white/55">{coordinates}</div>}
    </div>
  );
}

function eventTimeMs(event: Pick<GlobalEvent, "timestamp">) {
  if (!event.timestamp) return 0;
  const t = new Date(event.timestamp).getTime();
  return Number.isFinite(t) ? t : 0;
}

type BrowserMemoryPressure = "normal" | "medium" | "high";
type MapBoundsLike = { north: number; south: number; east: number; west: number };
type BboxLike = { west: number; south: number; east: number; north: number };

const EARTH_PROJECT_DETAIL_DELAY_MS = 1_500;
const EARTH_SIM_ASSET_READY_DELAY_MS = 2_500;
const EARTH_SIM_INFRA_READY_DELAY_MS = 750;
const OYSTER_PROJECT_BBOX: BboxLike = { west: -117.36, south: 32.43, east: -116.92, north: 32.82 };
const MOJAVE_PROJECT_BBOX: BboxLike = { west: -116.95, south: 34.35, east: -114.05, north: 36.55 };
const BAKED_INAT_REGIONS = ["sdtj", "nyc", "dc", "vegas", "la", "sf", "peninsula"] as const;
type BakedInatRegion = typeof BAKED_INAT_REGIONS[number];
const BAKED_INAT_REGION_BBOX: Record<BakedInatRegion, BboxLike> = {
  sdtj: OYSTER_PROJECT_BBOX,
  la: { west: -119.05, south: 33.25, east: -117.45, north: 34.65 },
  sf: { west: -123.15, south: 37.05, east: -121.65, north: 38.35 },
  peninsula: { west: -122.65, south: 36.95, east: -121.75, north: 37.8 },
  nyc: { west: -74.35, south: 40.35, east: -73.45, north: 41.05 },
  dc: { west: -77.75, south: 38.55, east: -76.55, north: 39.25 },
  vegas: { west: -115.55, south: 35.8, east: -114.75, north: 36.55 },
};

function boundsIntersectBbox(bounds: MapBoundsLike | null | undefined, bbox: BboxLike, paddingDegrees = 0) {
  if (!bounds) return false;
  const west = Math.max(-180, bbox.west - paddingDegrees);
  const east = Math.min(180, bbox.east + paddingDegrees);
  const south = Math.max(-85, bbox.south - paddingDegrees);
  const north = Math.min(85, bbox.north + paddingDegrees);
  if (bounds.north < south || bounds.south > north) return false;
  if (bounds.west <= bounds.east) {
    return bounds.east >= west && bounds.west <= east;
  }
  return east >= bounds.west || west <= bounds.east;
}

const RESOURCE_GOVERNOR_MS = 30_000;
const RESOURCE_LIMITS: Record<BrowserMemoryPressure, {
  nature: number;
  events: number;
  aircraft: number;
  vessels: number;
  satellites: number;
  streamed: number;
  lastKnown: number;
}> = {
  normal: { nature: 30_000, events: 1_200, aircraft: 1_500, vessels: 2_500, satellites: 1_200, streamed: 1_500, lastKnown: 3_500 },
  medium: { nature: 20_000, events: 900, aircraft: 1_000, vessels: 1_800, satellites: 900, streamed: 800, lastKnown: 2_400 },
  high: { nature: 12_000, events: 500, aircraft: 600, vessels: 1_200, satellites: 600, streamed: 500, lastKnown: 1_600 },
};
const EARTH_SIM_SAFE_RESOURCE_LIMITS = {
  nature: 30_000,
  events: 220,
  aircraft: 700,
  vessels: 900,
  satellites: 240,
  streamed: 180,
  lastKnown: 900,
};

function getEarthSimMoverRenderCap(kind: "aircraft" | "vessel" | "satellite", zoom: number): number {
  const z = Number.isFinite(zoom) ? zoom : 0;
  if (kind === "satellite") {
    if (z < 3) return 60;
    if (z < 5) return 80;
    if (z < 7) return 110;
    if (z < 10) return 140;
    return 180;
  }
  if (kind === "vessel") {
    if (z < 3) return 120;
    if (z < 5) return 160;
    if (z < 7) return 220;
    if (z < 10) return 280;
    return 340;
  }
  if (z < 3) return 140;
  if (z < 5) return 180;
  if (z < 7) return 240;
  if (z < 10) return 300;
  return 360;
}

function observationTimeMs(obs: Pick<FungalObservation, "observed_on">) {
  if (!obs.observed_on) return 0;
  const t = new Date(obs.observed_on).getTime();
  return Number.isFinite(t) ? t : 0;
}

function observationResourceRank(obs: FungalObservation) {
  const qualityBonus = obs.quality_grade === "research" ? 2_000 : 0;
  return observationTimeMs(obs) + qualityBonus;
}

function firstString(...values: unknown[]): string {
  for (const value of values) {
    if (typeof value === "string" && value.trim()) return value.trim();
    if (typeof value === "number" && Number.isFinite(value)) return String(value);
  }
  return "";
}

function firstNumber(...values: unknown[]): number {
  for (const value of values) {
    const n = Number(value);
    if (Number.isFinite(n)) return n;
  }
  return Number.NaN;
}

function extractMindexSpeciesRows(data: any): Record<string, any>[] {
  if (Array.isArray(data?.observations)) return data.observations;
  if (Array.isArray(data?.entities)) return data.entities;
  if (Array.isArray(data?.results)) return data.results;
  if (Array.isArray(data?.data)) return data.data;
  if (Array.isArray(data?.features)) {
    return data.features.map((feature: any) => ({
      ...(feature?.properties ?? {}),
      id: feature?.id ?? feature?.properties?.id,
      geometry: feature?.geometry,
      longitude: feature?.geometry?.coordinates?.[0],
      latitude: feature?.geometry?.coordinates?.[1],
    }));
  }
  return [];
}

function normalizeSpeciesRowToFungalObservation(row: Record<string, any>): FungalObservation | null {
  const props = row && typeof row.properties === "object" && row.properties ? row.properties : {};
  const taxon = row && typeof row.taxon === "object" && row.taxon ? row.taxon : {};
  const coords = Array.isArray(row?.geometry?.coordinates) ? row.geometry.coordinates : [];
  const latitude = firstNumber(row.latitude, row.lat, props.latitude, props.lat, coords[1]);
  const longitude = firstNumber(row.longitude, row.lng, row.lon, props.longitude, props.lng, props.lon, coords[0]);
  if (!Number.isFinite(latitude) || !Number.isFinite(longitude) || (latitude === 0 && longitude === 0)) return null;

  const observedOn = firstString(
    row.observed_on,
    row.observedOn,
    row.timestamp,
    row.occurred_at,
    props.observed_on,
    props.observedOn,
    props.timestamp,
    props.occurred_at,
  );
  const species = firstString(
    row.commonName,
    row.common_name,
    row.species,
    row.species_name,
    row.scientificName,
    row.scientific_name,
    row.name,
    props.commonName,
    props.common_name,
    props.species,
    props.species_name,
    props.scientificName,
    props.scientific_name,
    props.name,
    taxon.preferred_common_name,
    taxon.name,
  ) || "Unknown";
  const scientificName = firstString(
    row.scientificName,
    row.scientific_name,
    row.species_name,
    row.species,
    props.scientificName,
    props.scientific_name,
    props.species_name,
    props.species,
    taxon.name,
    species,
  ) || species;
  const commonName = firstString(row.commonName, row.common_name, props.commonName, props.common_name, taxon.preferred_common_name, species);
  const source = firstString(row.source, props.source, row.dataSource, props.dataSource, "MINDEX");
  const externalId = firstString(row.externalId, row.external_id, props.externalId, props.external_id, row.uuid, props.uuid);
  const id = firstString(row.id, props.id, externalId) ||
    `${source}:${scientificName}:${latitude.toFixed(5)}:${longitude.toFixed(5)}:${observedOn}`;
  const taxonId = firstNumber(row.taxon_id, row.taxonId, props.taxon_id, props.taxonId, taxon.id);
  const kingdom = firstString(
    row.kingdom,
    row.iconicTaxon,
    row.iconic_taxon_name,
    props.kingdom,
    props.iconicTaxon,
    props.iconic_taxon_name,
    taxon.iconic_taxon_name,
    "Unknown",
  );
  const imageUrl = firstString(row.imageUrl, row.image_url, row.thumbnailUrl, row.thumbnail_url, props.imageUrl, props.image_url, props.thumbnailUrl, props.thumbnail_url);
  const existingPhotos = Array.isArray(row.photos) ? row.photos : [];
  const photos = existingPhotos.length > 0
    ? existingPhotos.map((photo: any, index: number) => ({
        id: Number(photo?.id ?? index + 1),
        url: String(photo?.url ?? photo?.mediumUrl ?? photo?.medium_url ?? photo?.src ?? ""),
        license: firstString(photo?.license, photo?.attribution),
      })).filter((photo: { url: string }) => photo.url)
    : imageUrl
      ? [{ id: 1, url: imageUrl, license: firstString(row.license, props.license) || "CC-BY-NC" }]
      : [];

  return {
    id,
    observed_on: observedOn,
    latitude,
    longitude,
    species,
    taxon_id: Number.isFinite(taxonId) ? taxonId : undefined,
    taxon: {
      id: Number.isFinite(taxonId) ? taxonId : 0,
      name: scientificName,
      preferred_common_name: commonName || species,
      rank: firstString(taxon.rank, props.rank, "species"),
    },
    photos,
    quality_grade: firstString(row.quality_grade, row.qualityGrade, props.quality_grade, props.qualityGrade) || (row.verified ? "research" : "needs_id"),
    user: firstString(row.observer, row.user, row.user_name, props.observer, props.user, props.user_name),
    source,
    location: firstString(row.location, row.place_guess, props.location, props.place_guess),
    sourceUrl: firstString(row.sourceUrl, row.source_url, row.uri, props.sourceUrl, props.source_url, props.uri),
    externalId,
    kingdom,
    iconicTaxon: firstString(row.iconicTaxon, row.iconic_taxon_name, props.iconicTaxon, props.iconic_taxon_name, kingdom),
  };
}

type NatureKingdomBucket =
  | "Fungi"
  | "Plantae"
  | "Aves"
  | "Mammalia"
  | "Reptilia"
  | "Insecta"
  | "Marine"
  | "Other";

function normalizeNatureTaxonToken(value: unknown): string {
  return String(value ?? "").trim().toLowerCase();
}

const NON_FUNGAL_NATURE_TOKENS = new Set([
  "animalia",
  "plantae",
  "chromista",
  "protozoa",
  "bacteria",
  "archaea",
  "aves",
  "mammalia",
  "reptilia",
  "amphibia",
  "actinopterygii",
  "arachnida",
  "insecta",
  "mollusca",
]);

function observationHasExplicitNonFungiTaxon(obs: FungalObservation): boolean {
  const tokens = [
    obs.iconicTaxon,
    obs.kingdom,
    obs.taxon?.name,
  ].map(normalizeNatureTaxonToken);
  return tokens.some((token) => token && NON_FUNGAL_NATURE_TOKENS.has(token));
}

function isFungiOnlyNatureFilter(filter: GroundFilter): boolean {
  return (
    filter.showFungi &&
    !filter.showPlants &&
    !filter.showBirds &&
    !filter.showMammals &&
    !filter.showReptiles &&
    !filter.showInsects &&
    !filter.showMarineLife
  );
}

/** API kingdom param â€” Fungi when only fungi toggled (fast MINDEX index path). */
function natureBucketApiParam(bucket: NatureKingdomBucket): string {
  switch (bucket) {
    case "Fungi":
      return "Fungi";
    case "Plantae":
      return "Plantae";
    case "Aves":
      return "Aves";
    case "Mammalia":
      return "Mammalia";
    case "Reptilia":
      return "Reptilia";
    case "Insecta":
      return "Insecta";
    case "Marine":
      return "Actinopterygii";
    default:
      return "all";
  }
}

function natureBucketForGroundFilterKey(key: keyof GroundFilter): NatureKingdomBucket | null {
  switch (key) {
    case "showFungi":
      return "Fungi";
    case "showPlants":
      return "Plantae";
    case "showBirds":
      return "Aves";
    case "showMammals":
      return "Mammalia";
    case "showReptiles":
      return "Reptilia";
    case "showInsects":
      return "Insecta";
    case "showMarineLife":
      return "Marine";
    default:
      return null;
  }
}

function natureKingdomApiParam(filter: GroundFilter): string {
  const enabled = enabledNatureKingdomBuckets(filter);
  if (enabled.length === 1) {
    return natureBucketApiParam(enabled[0]);
  }
  if (enabled.length === 2 && enabled.includes("Fungi")) {
    const secondary = enabled.find((bucket) => bucket !== "Fungi");
    if (secondary) return natureBucketApiParam(secondary);
  }
  return "all";
}

function natureKingdomBucket(obs: FungalObservation): NatureKingdomBucket {
  const iconicToken = normalizeNatureTaxonToken(obs.iconicTaxon);
  const kingdomToken = normalizeNatureTaxonToken(obs.kingdom);
  const token = iconicToken && iconicToken !== "unknown" ? iconicToken : kingdomToken;
  switch (token) {
    case "fungi":
    case "fungus":
    case "mycota":
      return "Fungi";
    case "plantae":
    case "plants":
    case "plant":
      return "Plantae";
    case "aves":
    case "birds":
    case "bird":
      return "Aves";
    case "mammalia":
    case "mammals":
    case "mammal":
    case "cetacea":
      return "Mammalia";
    case "reptilia":
    case "amphibia":
    case "reptiles":
    case "reptile":
    case "amphibians":
    case "amphibian":
      return "Reptilia";
    case "insecta":
    case "arachnida":
    case "insects":
    case "insect":
    case "arachnids":
      return "Insecta";
    case "actinopterygii":
    case "mollusca":
    case "marine":
    case "fish":
    case "chondrichthyes":
      return "Marine";
    case "animalia":
      return "Other";
    default:
      return "Other";
  }
}

/** Client-side filter â€” must match enabled legend toggles instantly (no fetch wait). */
function observationMatchesNatureFilter(obs: FungalObservation, filter: GroundFilter): boolean {
  const bucket = natureKingdomBucket(obs);
  if (bucket === "Other") {
    // Never paint unclassified rows as fungi â€” avoids whales/rabbits with missing kingdom.
    if (isFungiOnlyNatureFilter(filter)) {
      return false;
    }
    // Multi-kingdom: show broad Animalia/unknown rows only when every bucket is enabled.
    if (enabledNatureKingdomCount(filter) >= 7) return true;
    if (observationHasExplicitNonFungiTaxon(obs)) return false;
    return false;
  }
  switch (bucket) {
    case "Fungi":
      return filter.showFungi;
    case "Plantae":
      return filter.showPlants;
    case "Aves":
      return filter.showBirds;
    case "Mammalia":
      return filter.showMammals;
    case "Reptilia":
      return filter.showReptiles;
    case "Insecta":
      return filter.showInsects;
    case "Marine":
      return filter.showMarineLife;
  }
}

function enabledNatureKingdomBuckets(filter: GroundFilter): NatureKingdomBucket[] {
  const buckets: NatureKingdomBucket[] = [];
  if (filter.showFungi) buckets.push("Fungi");
  if (filter.showPlants) buckets.push("Plantae");
  if (filter.showBirds) buckets.push("Aves");
  if (filter.showMammals) buckets.push("Mammalia");
  if (filter.showReptiles) buckets.push("Reptilia");
  if (filter.showInsects) buckets.push("Insecta");
  if (filter.showMarineLife) buckets.push("Marine");
  return buckets;
}

function enabledNatureKingdomCount(filter: GroundFilter): number {
  return enabledNatureKingdomBuckets(filter).length;
}

/** Fair cap split so fungi recency does not crowd out birds/plants on the globe. */
function pickStratifiedNatureObservations(
  observations: FungalObservation[],
  cap: number,
  filter: GroundFilter,
): FungalObservation[] {
  const enabled = enabledNatureKingdomBuckets(filter);
  if (enabled.length === 0 || cap <= 0) return [];
  const perBucket = Math.max(40, Math.ceil(cap / enabled.length));
  const picked: FungalObservation[] = [];
  const usedIds = new Set<string>();
  for (const bucket of enabled) {
    const bucketObs = observations
      .filter((obs) => natureKingdomBucket(obs) === bucket)
      .sort((a, b) => observationResourceRank(b) - observationResourceRank(a))
      .slice(0, perBucket);
    for (const obs of bucketObs) {
      const obsKey = String(obs.id);
      if (usedIds.has(obsKey)) continue;
      usedIds.add(obsKey);
      picked.push(obs);
    }
  }
  if (enabled.length > 1) {
    const unknownObs = observations
      .filter((obs) => natureKingdomBucket(obs) === "Other" && observationMatchesNatureFilter(obs, filter))
      .sort((a, b) => observationResourceRank(b) - observationResourceRank(a))
      .slice(0, perBucket);
    for (const obs of unknownObs) {
      const obsKey = String(obs.id);
      if (usedIds.has(obsKey)) continue;
      usedIds.add(obsKey);
      picked.push(obs);
    }
  }
  if (picked.length < cap) {
    const remainder = observations
      .filter((obs) => !usedIds.has(String(obs.id)) && observationMatchesNatureFilter(obs, filter))
      .sort((a, b) => observationResourceRank(b) - observationResourceRank(a))
      .slice(0, cap - picked.length);
    picked.push(...remainder);
  }
  return picked.slice(0, cap);
}

function spatiallySampleNatureBucket(
  observations: FungalObservation[],
  cap: number,
  bounds: MapBoundsLike | null | undefined,
  previousIds: Set<string>,
): FungalObservation[] {
  if (!Number.isFinite(cap) || observations.length <= cap) {
    return observations
      .slice()
      .sort((a, b) => observationResourceRank(b) - observationResourceRank(a));
  }
  if (cap <= 0) return [];

  const sorted = observations
    .slice()
    .sort((a, b) => observationResourceRank(b) - observationResourceRank(a));
  const latRange = Math.max(
    0.0001,
    bounds
      ? Math.abs(bounds.north - bounds.south)
      : Math.max(...sorted.map((obs) => obs.latitude)) - Math.min(...sorted.map((obs) => obs.latitude)),
  );
  const lngRange = Math.max(
    0.0001,
    bounds
      ? (bounds.west <= bounds.east
        ? Math.abs(bounds.east - bounds.west)
        : 360 - Math.abs(bounds.west - bounds.east))
      : Math.max(...sorted.map((obs) => obs.longitude)) - Math.min(...sorted.map((obs) => obs.longitude)),
  );
  const gridSize = Math.max(2, Math.ceil(Math.sqrt(cap)));
  const latCell = Math.max(0.00001, latRange / gridSize);
  const lngCell = Math.max(0.00001, lngRange / gridSize);
  const grid = new Map<string, FungalObservation>();

  const place = (obs: FungalObservation, stickyOnly: boolean) => {
    if (stickyOnly && !previousIds.has(String(obs.id ?? ""))) return;
    const cellX = Math.floor((obs.longitude + 180) / lngCell);
    const cellY = Math.floor((obs.latitude + 90) / latCell);
    const cellKey = `${cellX},${cellY}`;
    const existing = grid.get(cellKey);
    if (!existing) {
      grid.set(cellKey, obs);
      return;
    }
    if (previousIds.has(String(existing.id ?? ""))) return;
    if (observationResourceRank(obs) > observationResourceRank(existing)) {
      grid.set(cellKey, obs);
    }
  };

  for (const obs of sorted) place(obs, true);
  for (const obs of sorted) place(obs, false);

  const sampled = Array.from(grid.values())
    .sort((a, b) => observationResourceRank(b) - observationResourceRank(a));
  if (sampled.length >= cap) return sampled.slice(0, cap);

  const pickedIds = new Set(sampled.map((obs) => String(obs.id ?? "")));
  for (const obs of sorted) {
    const id = String(obs.id ?? "");
    if (!id || pickedIds.has(id)) continue;
    pickedIds.add(id);
    sampled.push(obs);
    if (sampled.length >= cap) break;
  }
  return sampled.slice(0, cap);
}

function spatiallySampleNatureObservations(
  observations: FungalObservation[],
  cap: number,
  filter: GroundFilter,
  bounds: MapBoundsLike | null | undefined,
  previousVisible: FungalObservation[] = [],
): FungalObservation[] {
  if (!Number.isFinite(cap) || observations.length <= cap) return observations;
  if (cap <= 0) return [];

  const enabledBuckets = enabledNatureKingdomBuckets(filter);
  const bucketOrder = enabledBuckets.length
    ? enabledBuckets
    : Array.from(new Set(observations.map((obs) => natureKingdomBucket(obs))));
  const activeBuckets = bucketOrder.filter((bucket) =>
    observations.some((obs) => natureKingdomBucket(obs) === bucket),
  );
  if (activeBuckets.length === 0) return observations.slice(0, cap);

  const previousIds = new Set(previousVisible.map((obs) => String(obs.id ?? "")));
  const observationsById = new Map(observations.map((obs) => [String(obs.id ?? ""), obs]));
  const picked: FungalObservation[] = [];
  const pickedIds = new Set<string>();
  const pickedBucketCounts = new Map<string, number>();
  const addObservation = (obs: FungalObservation) => {
    const id = String(obs.id ?? "");
    if (!id || pickedIds.has(id)) return false;
    pickedIds.add(id);
    picked.push(obs);
    const bucket = natureKingdomBucket(obs);
    pickedBucketCounts.set(bucket, (pickedBucketCounts.get(bucket) ?? 0) + 1);
    return true;
  };

  const previousStillVisible = previousVisible
    .map((obs) => observationsById.get(String(obs.id ?? "")))
    .filter((obs): obs is FungalObservation => !!obs && observationMatchesNatureFilter(obs, filter));
  const fungiRows = activeBuckets.includes("Fungi")
    ? observations.filter((obs) => natureKingdomBucket(obs) === "Fungi")
    : [];
  const protectedFungiMinimum = activeBuckets.length > 1 && fungiRows.length > 0
    ? Math.min(fungiRows.length, Math.max(80, Math.floor(cap * 0.35)))
    : 0;
  // Sticky retention carries prior-frame markers forward to avoid flicker
  // during a small pan. But keeping the full previous set (the single-bucket
  // case kept 100%) glued the dense origin cluster — e.g. a San Diego deep-dive
  // — to the screen on zoom-out, so the rest of the new viewport never painted.
  // Cap sticky to ~35% so fresh viewport-wide spatial sampling dominates and
  // species paint across the whole current view. (Jun 12, 2026 — Morgan:
  // "unpaint things that are older in the new area and show the newest species
  // in the entire viewport.")
  const STICKY_FRACTION = 0.35;
  const stickyLimitBase = Math.min(
    previousStillVisible.length,
    Math.max(0, Math.floor(cap * STICKY_FRACTION)),
  );
  const stickyLimit = protectedFungiMinimum > 0
    ? Math.min(stickyLimitBase, Math.max(0, cap - protectedFungiMinimum))
    : stickyLimitBase;
  for (const obs of previousStillVisible) {
    if (picked.length >= stickyLimit) break;
    addObservation(obs);
  }

  if (protectedFungiMinimum > 0 && picked.length < cap) {
    const sampledFungi = spatiallySampleNatureBucket(
      fungiRows,
      protectedFungiMinimum,
      bounds,
      previousIds,
    );
    for (const obs of sampledFungi) {
      if ((pickedBucketCounts.get("Fungi") ?? 0) >= protectedFungiMinimum || picked.length >= cap) break;
      addObservation(obs);
    }
  }

  if (activeBuckets.length > 1 && picked.length < cap) {
    const minimumPerBucket = Math.min(32, Math.max(12, Math.floor(cap / Math.max(3, activeBuckets.length * 3))));
    for (const bucket of activeBuckets) {
      if (picked.length >= cap) break;
      const alreadyPicked = pickedBucketCounts.get(bucket) ?? 0;
      if (alreadyPicked >= minimumPerBucket) continue;
      const rows = observations.filter((obs) => natureKingdomBucket(obs) === bucket);
      const sampled = spatiallySampleNatureBucket(rows, minimumPerBucket, bounds, previousIds);
      for (const obs of sampled) {
        if ((pickedBucketCounts.get(bucket) ?? 0) >= minimumPerBucket || picked.length >= cap) break;
        addObservation(obs);
      }
    }
  }

  const remainingSlots = Math.max(0, cap - picked.length);
  const baseBucketCap = Math.max(1, Math.floor(remainingSlots / activeBuckets.length));
  let remainder = Math.max(0, remainingSlots - baseBucketCap * activeBuckets.length);

  for (const bucket of activeBuckets) {
    if (picked.length >= cap) break;
    const bucketCap = baseBucketCap + (remainder > 0 ? 1 : 0);
    remainder = Math.max(0, remainder - 1);
    const rows = observations.filter((obs) => natureKingdomBucket(obs) === bucket);
    const sampled = spatiallySampleNatureBucket(rows, bucketCap, bounds, previousIds);
    for (const obs of sampled) {
      addObservation(obs);
      if (picked.length >= cap) break;
    }
  }

  if (picked.length < cap) {
    const fill = observations
      .filter((obs) => !pickedIds.has(String(obs.id ?? "")))
      .sort((a, b) => observationResourceRank(b) - observationResourceRank(a));
    for (const obs of fill) {
      addObservation(obs);
      if (picked.length >= cap) break;
    }
  }

  return picked.slice(0, cap);
}

function eventResourceRank(event: GlobalEvent) {
  return eventTimeMs(event) + earthquakeSeverityRank(event) * 60_000;
}

function entityResourceRank(entity: unknown) {
  const record = entity as Record<string, unknown>;
  const candidates = [
    record.lastUpdate,
    record.lastSeen,
    record.timestamp,
    record.updatedAt,
    record.updated_at,
    (record.properties as Record<string, unknown> | undefined)?.lastUpdate,
    (record.properties as Record<string, unknown> | undefined)?.timestamp,
  ];
  for (const value of candidates) {
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string") {
      const t = new Date(value).getTime();
      if (Number.isFinite(t)) return t;
    }
  }
  return 0;
}

function pruneStoreByRank<T>(
  store: Map<string, T>,
  maxEntries: number,
  getRank: (item: T) => number,
  keepId?: string | number | null,
  keepIds?: Iterable<string | number | null | undefined>,
) {
  if (store.size <= maxEntries) return false;
  const keep = new Set<string>();
  if (keepId != null) keep.add(String(keepId));
  if (keepIds) {
    for (const id of keepIds) {
      if (id != null) keep.add(String(id));
    }
  }
  const ranked = Array.from(store.entries()).sort((a, b) => getRank(b[1]) - getRank(a[1]));
  for (const [id] of ranked) {
    if (keep.size >= maxEntries) break;
    keep.add(id);
  }
  let changed = false;
  for (const id of Array.from(store.keys())) {
    if (!keep.has(id)) {
      store.delete(id);
      changed = true;
    }
  }
  return changed;
}

// Viewport-windowed prune. The plain rank prune above let a dense origin cluster
// (e.g. a San Diego deep-dive) survive forever because its observations rank
// high (recent + quality) and the store cap was rarely reached — so panning to a
// new region never dropped the stale cluster, and the unbounded store mounted
// hundreds of DOM markers (the freeze). This keeps the CURRENT viewport densely
// and retains only a small ranked buffer of off-screen observations for smooth
// zoom-out, deleting the rest. (Jun 12, 2026 — Morgan: LOD / "unpaint things
// that are older in the new area".)
function pruneStoreViewportFirst<T>(
  store: Map<string, T>,
  bounds: MapBoundsLike | null | undefined,
  isInViewport: (item: T, bounds: MapBoundsLike) => boolean,
  inViewportCap: number,
  outViewportCap: number,
  getRank: (item: T) => number,
  keepId?: string | number | null,
) {
  if (!bounds) return pruneStoreByRank(store, inViewportCap, getRank, keepId);
  const inView: Array<[string, T]> = [];
  const outView: Array<[string, T]> = [];
  for (const entry of store.entries()) {
    (isInViewport(entry[1], bounds) ? inView : outView).push(entry);
  }
  const keep = new Set<string>();
  if (keepId != null) keep.add(String(keepId));
  inView.sort((a, b) => getRank(b[1]) - getRank(a[1]));
  for (const [id] of inView) {
    if (keep.size >= inViewportCap) break;
    keep.add(id);
  }
  outView.sort((a, b) => getRank(b[1]) - getRank(a[1]));
  let outKept = 0;
  for (const [id] of outView) {
    if (outKept >= outViewportCap) break;
    keep.add(id);
    outKept += 1;
  }
  let changed = false;
  for (const id of Array.from(store.keys())) {
    if (!keep.has(id)) {
      store.delete(id);
      changed = true;
    }
  }
  return changed;
}

function pointInMapBounds(
  lat: number,
  lng: number,
  bounds: MapBoundsLike | null | undefined,
  paddingDegrees = 0,
) {
  if (!bounds) return false;
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return false;
  const south = bounds.south - paddingDegrees;
  const north = bounds.north + paddingDegrees;
  if (lat < south || lat > north) return false;
  const west = bounds.west - paddingDegrees;
  const east = bounds.east + paddingDegrees;
  if (bounds.west > bounds.east) return lng >= west || lng <= east;
  return lng >= west && lng <= east;
}

function eventInMapBounds(event: GlobalEvent, bounds: MapBoundsLike | null | undefined, paddingDegrees = 0) {
  const lat = Number(event.lat);
  const lng = Number(event.lng);
  return pointInMapBounds(lat, lng, bounds, paddingDegrees);
}

function observationInMapBounds(obs: FungalObservation, bounds: MapBoundsLike | null | undefined, paddingDegrees = 0) {
  const lat = Number(obs.latitude);
  const lng = Number(obs.longitude);
  return pointInMapBounds(lat, lng, bounds, paddingDegrees);
}

function storeIdsInViewport<T>(
  store: Map<string, T>,
  bounds: MapBoundsLike | null | undefined,
  isInViewport: (item: T, bounds: MapBoundsLike) => boolean,
) {
  const keep = new Set<string>();
  if (!bounds) return keep;
  for (const [id, item] of store.entries()) {
    if (isInViewport(item, bounds)) keep.add(id);
  }
  return keep;
}

function clampArrayByRank<T>(
  items: T[],
  maxEntries: number,
  getRank: (item: unknown) => number,
) {
  if (items.length <= maxEntries) return items;
  return [...items].sort((a, b) => getRank(b) - getRank(a)).slice(0, maxEntries);
}

function clampArrayByRankPreservingViewport<T>(
  items: T[],
  maxEntries: number,
  getRank: (item: unknown) => number,
  bounds?: MapBoundsLike | null,
  keepTokens?: Iterable<string | number | null | undefined>,
) {
  if (!Number.isFinite(maxEntries) || items.length <= maxEntries) return items;
  const keep = new Set<string>();
  if (keepTokens) {
    for (const token of keepTokens) {
      if (token != null) keep.add(String(token).toLowerCase());
    }
  }
  const viewport: T[] = [];
  const outside: T[] = [];
  for (const item of items) {
    const coord = readAssetCoord(item as any);
    const tokens = assetIdentity(item as any);
    const selected = tokens.some((token) => keep.has(token));
    const inViewport = coord ? pointInMapBounds(coord.lat, coord.lng, bounds, 0.25) : false;
    if (selected || inViewport) viewport.push(item);
    else outside.push(item);
  }
  if (viewport.length >= maxEntries) return viewport;
  const remaining = maxEntries - viewport.length;
  return [
    ...viewport,
    ...outside.sort((a, b) => getRank(b) - getRank(a)).slice(0, remaining),
  ];
}

function getBrowserMemoryPressure(): BrowserMemoryPressure {
  if (typeof performance === "undefined") return "normal";
  const memory = (performance as unknown as {
    memory?: { usedJSHeapSize?: number; jsHeapSizeLimit?: number };
  }).memory;
  const used = Number(memory?.usedJSHeapSize);
  const limit = Number(memory?.jsHeapSizeLimit);
  if (!Number.isFinite(used) || !Number.isFinite(limit) || limit <= 0) return "normal";
  const ratio = used / limit;
  if (ratio >= 0.82) return "high";
  if (ratio >= 0.68) return "medium";
  return "normal";
}

function earthquakeSeverityRank(event: Pick<GlobalEvent, "severity" | "magnitude">) {
  const mag = Number(event.magnitude);
  if (Number.isFinite(mag)) return Math.max(0, Math.min(6, mag));
  const ranks: Record<string, number> = { extreme: 6, critical: 5, high: 4, medium: 3, low: 2, info: 1 };
  return ranks[event.severity || "info"] ?? 0;
}

function applyEarthquakeSearchLOD(events: GlobalEvent[], zoom: number) {
  void zoom;
  return [...events].sort((a, b) => {
    const dt = eventTimeMs(b) - eventTimeMs(a);
    if (dt !== 0) return dt;
    return earthquakeSeverityRank(b) - earthquakeSeverityRank(a);
  });
}

