const SPACE_WEATHER_ICON_EVENT_TYPES = new Set([
  "solar_flare",
  "geomagnetic_storm",
  "aurora",
  "cme",
  "solar_wind",
  "sun_earth_impact",
  "sun-earth-impact",
  "radiation_belt",
]);

function shouldSuppressEventIcon(type: string | undefined) {
  const normalized = (type || "").toLowerCase().trim();
  return SPACE_WEATHER_ICON_EVENT_TYPES.has(normalized);
}

function hasRenderableEventCoordinates(event: any) {
  const lat = event?.location?.latitude;
  const lng = event?.location?.longitude;
  if (typeof lat !== "number" || typeof lng !== "number") return false;
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return false;
  // Null-island defaults from upstream should not render as real-world events.
  if (Math.abs(lat) < 0.01 && Math.abs(lng) < 0.01) return false;
  return true;
}

function eventTypeBucketKey(event: GlobalEvent) {
  const t = (event.type || "").toLowerCase();
  if (t === "earthquake") return "earthquake";
  if (t === "wildfire" || t === "fire") return "wildfire";
  if (t === "volcano") return "volcano";
  if (t === "lightning") return "lightning";
  if (t === "tornado") return "tornado";
  if (t === "flood" || t === "tsunami" || t === "landslide") return "flood";
  if (["storm", "hurricane", "typhoon", "cyclone", "blizzard", "heatwave", "coldwave", "air_quality", "drought"].includes(t)) return "storm";
  if (t === "device" || t === "mycobrain") return "device";
  return "other";
}

function selectDiverseEvents(events: GlobalEvent[], cap: number) {
  if (events.length <= cap) return events;
  const buckets = new Map<string, GlobalEvent[]>();
  for (const event of events) {
    const key = eventTypeBucketKey(event);
    if (!buckets.has(key)) buckets.set(key, []);
    buckets.get(key)!.push(event);
  }
  for (const entries of buckets.values()) {
    entries.sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  }
  const orderedKeys = Array.from(buckets.keys()).sort();
  const selected: GlobalEvent[] = [];
  let cursor = 0;
  while (selected.length < cap && orderedKeys.length > 0) {
    const key = orderedKeys[cursor % orderedKeys.length];
    const bucket = buckets.get(key);
    if (bucket && bucket.length > 0) {
      selected.push(bucket.shift()!);
      cursor += 1;
      continue;
    }
    buckets.delete(key);
    orderedKeys.splice(cursor % orderedKeys.length, 1);
    if (orderedKeys.length === 0) break;
  }
  return selected;
}

function spatiallySampleEventBucket(
  events: GlobalEvent[],
  cap: number,
  previousIds: Set<string>,
): GlobalEvent[] {
  if (!Number.isFinite(cap) || events.length <= cap) {
    return events.slice().sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  }
  if (cap <= 0) return [];

  const sorted = events.slice().sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  const latRange = Math.max(
    0.0001,
    Math.max(...sorted.map((event) => Number(event.lat))) - Math.min(...sorted.map((event) => Number(event.lat))),
  );
  const lngRange = Math.max(
    0.0001,
    Math.max(...sorted.map((event) => Number(event.lng))) - Math.min(...sorted.map((event) => Number(event.lng))),
  );
  const gridSize = Math.max(2, Math.ceil(Math.sqrt(cap)));
  const latCell = Math.max(0.00001, latRange / gridSize);
  const lngCell = Math.max(0.00001, lngRange / gridSize);
  const grid = new Map<string, GlobalEvent>();

  const place = (event: GlobalEvent, stickyOnly: boolean) => {
    const id = String(event.id ?? "");
    if (stickyOnly && !previousIds.has(id)) return;
    const lat = Number(event.lat);
    const lng = Number(event.lng);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) return;
    const cellX = Math.floor((lng + 180) / lngCell);
    const cellY = Math.floor((lat + 90) / latCell);
    const cellKey = `${cellX},${cellY}`;
    const existing = grid.get(cellKey);
    if (!existing) {
      grid.set(cellKey, event);
      return;
    }
    if (previousIds.has(String(existing.id ?? ""))) return;
    if (eventResourceRank(event) > eventResourceRank(existing)) {
      grid.set(cellKey, event);
    }
  };

  for (const event of sorted) place(event, true);
  for (const event of sorted) place(event, false);

  const sampled = Array.from(grid.values())
    .sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  if (sampled.length >= cap) return sampled.slice(0, cap);

  const pickedIds = new Set(sampled.map((event) => String(event.id ?? "")));
  for (const event of sorted) {
    const id = String(event.id ?? "");
    if (!id || pickedIds.has(id)) continue;
    pickedIds.add(id);
    sampled.push(event);
    if (sampled.length >= cap) break;
  }
  return sampled.slice(0, cap);
}

function selectDistributedEvents(
  events: GlobalEvent[],
  cap: number,
  previousVisible: GlobalEvent[] = [],
): GlobalEvent[] {
  if (!Number.isFinite(cap) || events.length <= cap) return events;
  if (cap <= 0) return [];

  const previousIds = new Set(previousVisible.map((event) => String(event.id ?? "")));
  const bucketOrder = ["earthquake", "wildfire", "storm", "flood", "lightning", "volcano", "tornado", "other"];
  const buckets = new Map<string, GlobalEvent[]>();
  for (const event of events) {
    const key = eventTypeBucketKey(event);
    const rows = buckets.get(key) || [];
    rows.push(event);
    buckets.set(key, rows);
  }
  const activeBuckets = bucketOrder.filter((key) => (buckets.get(key)?.length || 0) > 0);
  for (const key of buckets.keys()) {
    if (!activeBuckets.includes(key)) activeBuckets.push(key);
  }
  if (activeBuckets.length === 0) return selectDiverseEvents(events, cap);

  const picked: GlobalEvent[] = [];
  const pickedIds = new Set<string>();
  const baseBucketCap = Math.max(1, Math.floor(cap / activeBuckets.length));
  let remainder = Math.max(0, cap - baseBucketCap * activeBuckets.length);

  for (const key of activeBuckets) {
    const rows = buckets.get(key) || [];
    const bucketCap = baseBucketCap + (remainder > 0 ? 1 : 0);
    remainder = Math.max(0, remainder - 1);
    const sampled = spatiallySampleEventBucket(rows, bucketCap, previousIds);
    for (const event of sampled) {
      const id = String(event.id ?? "");
      if (!id || pickedIds.has(id)) continue;
      pickedIds.add(id);
      picked.push(event);
    }
  }

  if (picked.length < cap) {
    const fill = events
      .filter((event) => !pickedIds.has(String(event.id ?? "")))
      .sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
    for (const event of fill) {
      const id = String(event.id ?? "");
      if (!id || pickedIds.has(id)) continue;
      pickedIds.add(id);
      picked.push(event);
      if (picked.length >= cap) break;
    }
  }

  return picked
    .sort((a, b) => eventResourceRank(b) - eventResourceRank(a))
    .slice(0, cap);
}

const RECENT_PRIORITY_WINDOW_MS = 72 * 60 * 60 * 1000;
const HOUR_MS = 60 * 60 * 1000;

function getEarthSimViewportPerfClass(): "desktop" | "tablet" | "phone" {
  if (typeof window === "undefined") return "desktop";
  const width = window.innerWidth || 1440;
  const coarsePointer = window.matchMedia?.("(pointer: coarse)")?.matches ?? false;
  // iPadOS Safari requests desktop sites by default and, with a Magic Keyboard /
  // trackpad attached, reports (pointer: fine). So an iPad Pro in landscape
  // (1366px on 12.9", 1194px on 11" — both > 1180) was classified "desktop" and
  // handed the full desktop budget (all overlays + 900 DOM markers + full-density
  // GeoJSON infra), which a tablet-class GPU cannot survive → immediate freeze.
  // maxTouchPoints is the one signal iPadOS does NOT spoof (it reports 5), so use
  // it to force any genuine multi-touch device to AT MOST "tablet" regardless of
  // width or pointer type. (Jun 13, 2026 — iPad Pro freeze P0 from live QA audit.)
  const touch = typeof navigator !== "undefined" && (navigator.maxTouchPoints ?? 0) > 1;
  if (width <= 767 || ((coarsePointer || touch) && width <= 900)) return "phone";
  if (width <= 1180 || coarsePointer || touch) return "tablet";
  return "desktop";
}

function getEarthSimGlobalEventApiLimit(): number {
  const perfClass = getEarthSimViewportPerfClass();
  if (perfClass === "phone") return 220;
  if (perfClass === "tablet") return 360;
  return 420;
}

function getInitialProjectionMode(): ProjectionMode {
  if (typeof window === "undefined") return "globe";
  return shouldStartInGlobeProjection() ? "globe" : "mercator";
}

function shouldStartInGlobeProjection(): boolean {
  // The Earth Simulator must ALWAYS open in the globe projection, never the flat
  // mercator map — on every device including iPad. The earlier width/pointer gate
  // downgraded touch/tablet/narrow viewports to mercator for GPU safety, but that
  // is the wrong default: globe is the intended experience everywhere, and the
  // user can still switch to map via the GlobeToggle. (Jun 13, 2026 — Morgan:
  // "should always open in the globe, never open in the map.")
  return true;
}

function isGlobeProjectionSafeForViewport(): boolean {
  return true;
}

function getEventDomMarkerCapForZoom(zoom: number, earthSimulator = false) {
  if (earthSimulator) {
    const baseCap = getEarthSimulatorEventDomCap(zoom);
    const perfClass = getEarthSimViewportPerfClass();
    if (perfClass === "phone") {
      const phoneCap =
        zoom >= 9 ? 90 :
        zoom >= 7 ? 80 :
        zoom >= 5 ? 70 :
        zoom >= 3 ? 60 :
        50;
      return Math.min(baseCap, phoneCap);
    }
    if (perfClass === "tablet") {
      const tabletCap =
        zoom >= 9 ? 180 :
        zoom >= 7 ? 160 :
        zoom >= 5 ? 140 :
        zoom >= 3 ? 120 :
        100;
      return Math.min(baseCap, tabletCap);
    }
    return baseCap;
  }
  // City/metro: no DOM cap â€” every enabled event in viewport renders.
  if (zoom >= 9) return UNCAPPED_RENDER_LIMIT;
  // Aggressive world-view budget to protect FPS during refresh/pan.
  if (zoom < 3) return 180;
  if (zoom < 5) return 280;
  if (zoom < 7) return 480;
  if (zoom < 9) return 800;
  return UNCAPPED_RENDER_LIMIT;
}

/** Zoom-tier DOM budget for FungalMarker â€” always capped so MapLibre WebGL stays at 30+ FPS. */
function getNatureDomMarkerCapForZoom(
  zoom: number,
  enabledKingdoms = 7,
  earthSimulator = false,
  bounds?: { north: number; south: number; east: number; west: number } | null,
): number {
  void bounds;
  const kingdomScale = Math.min(1, Math.max(0.45, enabledKingdoms / 7));
  if (earthSimulator) {
    const perfClass = getEarthSimViewportPerfClass();
    if (perfClass === "phone") {
      const phoneCap =
        zoom >= 11 ? 420 :
        zoom >= 9 ? 340 :
        zoom >= 7 ? 280 :
        zoom >= 5 ? 220 :
        zoom >= 3 ? 160 :
        110;
      return Math.max(60, Math.floor(phoneCap * kingdomScale));
    }
    if (perfClass === "tablet") {
      const tabletCap =
        zoom >= 11 ? 760 :
        zoom >= 9 ? 660 :
        zoom >= 7 ? 560 :
        zoom >= 5 ? 460 :
        zoom >= 3 ? 320 :
        220;
      return Math.min(EARTH_SIM_DOM_MARKER_CAP, Math.max(120, Math.floor(tabletCap * kingdomScale)));
    }
    const tierCap =
      zoom >= 11 ? 900 :
      zoom >= 9 ? 850 :
      zoom >= 7 ? 760 :
      zoom >= 5 ? 680 :
      zoom >= 3 ? 520 :
      360;
    return Math.min(EARTH_SIM_DOM_MARKER_CAP, Math.max(240, Math.floor(tierCap * kingdomScale)));
  }
  const tierCap =
    zoom >= 11 ? 1400 :
    zoom >= 9 ? 1200 :
    zoom >= 7 ? 900 :
    zoom >= 5 ? 650 :
    zoom >= 3 ? 450 :
    350;
  return Math.min(NATURE_DOM_MARKER_CAP, tierCap);
}

function getMaxEventAgeMsForZoom(_zoom: number): number {
  return MAP_DISPLAY_MAX_EVENT_AGE_MS;
}

function getMaxNatureAgeMsForZoom(_zoom: number): number {
  if (_zoom >= 8) return Number.POSITIVE_INFINITY;
  if (_zoom >= 5) return 5 * 365 * 86400_000;
  return MAP_DISPLAY_MAX_NATURE_AGE_MS;
}

function getNatureBudgetMultiplierForZoom(zoom: number): number {
  // Full budget at all zoom levels. Spatial sampling downstream keeps the
  // map stable without dropping to tiny visible counts.
  return 1;
}

function getEventTimestampMs(event: GlobalEvent): number {
  const raw =
    (event as any).timestamp ??
    (event as any).updated_at ??
    (event as any).updatedAt ??
    (event as any).created_at ??
    (event as any).createdAt ??
    0;
  if (typeof raw === "number") return Number.isFinite(raw) ? raw : 0;
  if (typeof raw === "string") {
    const parsed = new Date(raw).getTime();
    return Number.isFinite(parsed) ? parsed : 0;
  }
  return 0;
}

function isRecentPriorityEvent(event: GlobalEvent, nowMs = Date.now()) {
  const ts = getEventTimestampMs(event);
  return ts > 0 && ts >= nowMs - RECENT_PRIORITY_WINDOW_MS;
}

function isSpaceWeatherGlobalEvent(event: GlobalEvent): boolean {
  const t = (event.type || "").toLowerCase();
  const sub = ((event as { subtype?: string }).subtype || "").toLowerCase();
  return (
    SPACE_WEATHER_ICON_EVENT_TYPES.has(t) ||
    sub === "solar_radiation" ||
    sub === "radio_blackout" ||
    sub.includes("aurora")
  );
}

function padMapBoundsForEvents(bounds: MapBoundsLike): MapBoundsLike {
  const latPad = Math.min(15, Math.abs(bounds.north - bounds.south) * 0.25);
  const lngSpan =
    bounds.west <= bounds.east
      ? bounds.east - bounds.west
      : 360 - (bounds.west - bounds.east);
  const lngPad = Math.min(30, Math.abs(lngSpan) * 0.25);
  return {
    north: Math.min(90, bounds.north + latPad),
    south: Math.max(-90, bounds.south - latPad),
    east: bounds.east + lngPad,
    west: bounds.west - lngPad,
  };
}

function sortEventsByRecency(events: GlobalEvent[]): GlobalEvent[] {
  return [...events].sort((a, b) => {
    const ta = getEventTimestampMs(a);
    const tb = getEventTimestampMs(b);
    if (tb !== ta) return tb - ta;
    return eventResourceRank(b) - eventResourceRank(a);
  });
}

/** MYCA panel feed â€” recency-sorted viewport events, not map DOM/LOD capped. */
function selectMycaLatestViewportEvents(
  events: GlobalEvent[],
  bounds: MapBoundsLike | null,
  limit = 20,
): GlobalEvent[] {
  const nowMs = Date.now();
  const ageEligible = events.filter((event) => {
    const ts = getEventTimestampMs(event);
    return ts > 0 && ts >= nowMs - MAP_DISPLAY_MAX_EVENT_AGE_MS;
  });
  if (!bounds) {
    return sortEventsByRecency(ageEligible).slice(0, limit);
  }
  const padded = padMapBoundsForEvents(bounds);
  const inViewport = ageEligible.filter((event) => {
    if (isSpaceWeatherGlobalEvent(event)) return true;
    return eventInMapBounds(event, padded, 0);
  });
  return sortEventsByRecency(inViewport).slice(0, limit);
}

function getHistoricalBudgetForZoom(zoom: number, lodCap: number) {
  if (zoom < 3) return Math.max(30, Math.floor(lodCap * 0.12));
  if (zoom < 5) return Math.max(55, Math.floor(lodCap * 0.2));
  if (zoom < 7) return Math.max(100, Math.floor(lodCap * 0.32));
  if (zoom < 9) return Math.max(180, Math.floor(lodCap * 0.5));
  if (zoom < 11) return Math.max(260, Math.floor(lodCap * 0.68));
  return Math.max(380, Math.floor(lodCap * 0.88));
}

function selectViewportEventsWithPriority(
  events: GlobalEvent[],
  previousVisible: GlobalEvent[],
  zoom: number,
  lodCap: number,
): GlobalEvent[] {
  if (events.length === 0) {
    return previousVisible.length > 0 ? previousVisible : [];
  }

  const hardCap = getEventDomMarkerCapForZoom(zoom);
  if (!Number.isFinite(hardCap) || !Number.isFinite(lodCap)) {
    const byId = new Map<string, GlobalEvent>();
    for (const event of events) byId.set(String(event.id ?? ""), event);
    return Array.from(byId.values()).sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  }

  const baseCap = Math.max(1, Math.min(hardCap, lodCap));
  const nowMs = Date.now();

  const byId = new Map<string, GlobalEvent>();
  for (const event of events) byId.set(String(event.id ?? ""), event);
  const deduped = Array.from(byId.values());
  const maxEventAgeMs = getMaxEventAgeMsForZoom(zoom);
  const ageFiltered = Number.isFinite(maxEventAgeMs)
    ? deduped.filter((event) => {
        const ts = getEventTimestampMs(event);
        return ts === 0 || ts >= nowMs - maxEventAgeMs;
      })
    : deduped;

  const recent = ageFiltered
    .filter((event) => isRecentPriorityEvent(event, nowMs))
    .sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  const recentIds = new Set(recent.map((event) => String(event.id ?? "")));

  const historicalCandidates = ageFiltered
    .filter((event) => !recentIds.has(String(event.id ?? "")))
    .sort((a, b) => eventResourceRank(b) - eventResourceRank(a));
  const previousIds = new Set(previousVisible.map((event) => String(event.id ?? "")));

  const dynamicTarget = Math.min(
    hardCap,
    Math.max(
      baseCap,
      recent.length + getHistoricalBudgetForZoom(zoom, baseCap),
      recent.length,
    ),
  );

  if (recent.length >= dynamicTarget) {
    return selectDistributedEvents(recent, dynamicTarget, previousVisible);
  }

  const stickyHistorical = historicalCandidates.filter((event) =>
    previousIds.has(String(event.id ?? "")),
  );
  const stickyIds = new Set(stickyHistorical.map((event) => String(event.id ?? "")));
  const freshHistorical = historicalCandidates.filter(
    (event) => !stickyIds.has(String(event.id ?? "")),
  );
  const neededHistorical = Math.max(0, dynamicTarget - recent.length);
  const selectedHistorical = [...stickyHistorical, ...freshHistorical].slice(0, neededHistorical);

  return selectDistributedEvents([...recent, ...selectedHistorical], dynamicTarget, previousVisible);
}

