function findEarthMycaEventKey(text: string): EarthMycaEventKey | null {
  return EARTH_MYCA_EVENT_PATTERNS.find((entry) => entry.re.test(text))?.key || null;
}

function findEarthMycaKnownLocation(text: string) {
  const lower = text.toLowerCase();
  return EARTH_MYCA_LOCATIONS.find((loc) => loc.aliases.some((alias) => lower.includes(alias)));
}

function stripEarthMycaLocationQuery(text: string, eventKey: EarthMycaEventKey | null): string {
  let next = text
    .toLowerCase()
    .replace(/\b(?:show|fly|go|take|zoom|navigate|send|move|find|search)\b/g, " ")
    .replace(/\b(?:me|us|to|into|on|at|over|around|near|for|all|of|the|let|see|i|want|in|across)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (eventKey) {
    for (const entry of EARTH_MYCA_EVENT_PATTERNS) {
      if (entry.key === eventKey) next = next.replace(entry.re, " ").replace(/\s+/g, " ").trim();
    }
  }
  return next;
}

function buildEarthMycaEventPatch(eventKey: EarthMycaEventKey): Partial<GroundFilter> {
  return {
    showFungi: false,
    showPlants: false,
    showBirds: false,
    showMammals: false,
    showReptiles: false,
    showInsects: false,
    showMarineLife: false,
    showEarthquakes: eventKey === "showEarthquakes",
    showVolcanoes: eventKey === "showVolcanoes",
    showWildfires: eventKey === "showWildfires",
    showStorms: eventKey === "showStorms",
    showLightning: eventKey === "showLightning",
    showTornadoes: eventKey === "showTornadoes",
    showFloods: eventKey === "showFloods",
    showFactories: false,
    showPowerPlants: false,
    showMining: false,
    showOilGas: false,
    showWaterPollution: false,
    showMilitaryBases: false,
    showMycoBrain: false,
    showSporeBase: false,
    showSmartFence: false,
    showPartnerNetworks: false,
  };
}

async function geocodeEarthMycaLocation(query: string) {
  const clean = query.trim();
  if (!clean) return null;
  try {
    const res = await fetch(`/api/crep/geocode?q=${encodeURIComponent(clean)}`, {
      cache: "no-store",
      signal: AbortSignal.timeout(5_000),
    });
    if (!res.ok) return null;
    const data = await res.json();
    const hit = Array.isArray(data?.results) ? data.results[0] : data;
    const lat = Number(hit?.lat ?? hit?.latitude ?? hit?.center?.lat);
    const lng = Number(hit?.lng ?? hit?.lon ?? hit?.longitude ?? hit?.center?.lng);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
    return {
      name: String(hit?.name || hit?.label || hit?.display_name || clean),
      lat,
      lng,
      zoom: 11,
      aliases: [clean.toLowerCase()],
    };
  } catch {
    return null;
  }
}

function applyAssetIsolationToLayers(
  sourceLayers: LayerConfig[],
  mode: AssetIsolationMode,
  activeFungalLayerIds: Set<string>,
): LayerConfig[] {
  if (mode !== "funga" && mode !== "assets-off") return sourceLayers;
  return sourceLayers.map((layer) => ({
    ...layer,
    enabled: activeFungalLayerIds.has(layer.id) || FUNGA_BASE_CONTEXT_LAYER_IDS.has(layer.id),
    opacity: FUNGA_LAYER_OPACITY[layer.id] ?? layer.opacity,
  }));
}

function applyRequestedFungalLayersToLayers(
  sourceLayers: LayerConfig[],
  requestedFungalLayerIds: Set<string> | null,
): LayerConfig[] {
  if (!requestedFungalLayerIds) return sourceLayers;
  return sourceLayers.map((layer) => FUNGAL_ATLAS_LAYER_IDS.includes(layer.id as any)
    ? { ...layer, enabled: requestedFungalLayerIds.has(layer.id) }
    : layer
  );
}

function applyFiltersOffToLayers(sourceLayers: LayerConfig[]): LayerConfig[] {
  return sourceLayers.map((layer) => ({
    ...layer,
    enabled: FUNGA_BASE_CONTEXT_LAYER_IDS.has(layer.id),
    opacity: FUNGA_LAYER_OPACITY[layer.id] ?? layer.opacity,
  }));
}

function applyForceOffToLayers(sourceLayers: LayerConfig[]): LayerConfig[] {
  return sourceLayers.map((layer) =>
    FORCE_OFF_UNTIL_STABLE_LAYER_IDS.has(layer.id)
      ? { ...layer, enabled: false }
      : layer
  );
}

function persistFungaSelection(mode: AssetIsolationMode, activeFungalLayerIds?: Iterable<string>) {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.removeItem("crep_asset_isolation");
    window.localStorage.removeItem("crep_fungal_layers");
  } catch {
    /* ignore private browsing/storage failures */
  }
}

function isolateFungaMapLayers(map: any, includeFungi: boolean) {
  if (!map?.getStyle || !map?.setLayoutProperty) return;
  const keepPrefixes = [
    "crep-bathymetry",
    "crep-topo",
    "crep-satimagery",
    // Keep live aircraft visible even when fungal atlas overlays are enabled.
    "crep-live-aircraft",
  ];
  try {
    const styleLayers = map.getStyle()?.layers || [];
    for (const layer of styleLayers) {
      const id = layer?.id;
      if (!id || !id.startsWith("crep-")) continue;
      if (id.startsWith("crep-fungal-atlas")) {
        if (!includeFungi) map.setLayoutProperty(id, "visibility", "none");
        continue;
      }
      const visible = keepPrefixes.some((prefix) => id.startsWith(prefix));
      map.setLayoutProperty(id, "visibility", visible ? "visible" : "none");
    }
    const emptyFC = { type: "FeatureCollection", features: [] };
    const sourcesToClear = [
      "crep-live-buoys",
      "crep-live-vessels",
      "crep-live-satellites",
      "crep-live-satellite-orbits",
      "crep-celltowers",
      "crep-celltowers-global",
      "crep-celltowers-bbox",
      "crep-live-military",
      "crep-mycosoft-devices",
    ];
    for (const sourceId of sourcesToClear) {
      const source = map.getSource?.(sourceId);
      if (source?.setData) source.setData(emptyFC);
    }
    if (map.getLayer?.("crep-satimagery-raster")) {
      map.setPaintProperty("crep-satimagery-raster", "raster-opacity", includeFungi ? 0.08 : 0.28);
    }
  } catch {
    /* map may be tearing down during hot reload */
  }
}

function clearFungalAtlasMapLayers(map: any) {
  if (!map?.getStyle) return;
  try {
    const style = map.getStyle?.();
    const styleLayers = [...(style?.layers || [])].reverse();
    const emptyFC = { type: "FeatureCollection", features: [] };
    for (const layer of styleLayers) {
      const id = String(layer?.id || "");
      if (!id.startsWith("crep-fungal-atlas")) continue;
      try {
        if (map.getLayer?.(id)) map.setLayoutProperty(id, "visibility", "none");
      } catch {
        /* ignore style churn */
      }
    }
    const sources = style?.sources || {};
    for (const sourceId of Object.keys(sources)) {
      if (!sourceId.startsWith("crep-fungal-atlas")) continue;
      try {
        const source = map.getSource?.(sourceId);
        if (source?.setData) source.setData(emptyFC);
      } catch {
        /* raster/image/vector sources do not all support setData */
      }
    }
  } catch {
    /* map may still be loading */
  }
}

function hideAuditMapLayers(map: any) {
  if (!map?.getStyle || !map?.setLayoutProperty) return;
  try {
    clearFungalAtlasMapLayers(map);
    const keepPrefixes = [
      "crep-bathymetry",
      "crep-topo",
      "crep-satimagery",
    ];
    const styleLayers = map.getStyle()?.layers || [];
    for (const layer of styleLayers) {
      const id = layer?.id;
      if (!id) continue;
      if (keepPrefixes.some((prefix) => id.startsWith(prefix))) {
        map.setLayoutProperty(id, "visibility", "visible");
        continue;
      }
      if (
        id.startsWith("crep-") ||
        id.startsWith("earth2-") ||
        id.startsWith("gibs-") ||
        id.startsWith("nasa-")
      ) {
        map.setLayoutProperty(id, "visibility", "none");
      }
    }
    const emptyFC = { type: "FeatureCollection", features: [] };
    for (const sourceId of [
      "crep-live-buoys",
      "crep-live-aircraft",
      "crep-live-vessels",
      "crep-live-satellites",
      "crep-live-satellite-orbits",
      "crep-celltowers",
      "crep-celltowers-global",
      "crep-celltowers-bbox",
      "crep-live-military",
      "crep-mycosoft-devices",
      "crep-search-earthquake-events",
      "crep-earthquakes",
      "crep-volcanoes",
      "crep-wildfires",
      "crep-storms",
      "crep-lightning",
      "crep-tornadoes",
    ]) {
      const source = map.getSource?.(sourceId);
      if (source?.setData) source.setData(emptyFC);
    }
  } catch {
    /* map may still be loading */
  }
}

function fungalEnabledSnapshot(activeFungalLayerIds: Set<string>) {
  return {
    mycelium: activeFungalLayerIds.has("fungalAtlasMycelium"),
    am: activeFungalLayerIds.has("fungalAtlasAM"),
    ecm: activeFungalLayerIds.has("fungalAtlasECM"),
    rarity: activeFungalLayerIds.has("fungalAtlasRare"),
    endemic: activeFungalLayerIds.has("fungalAtlasRare"),
    protected: activeFungalLayerIds.has("fungalAtlasProtected"),
    uncertainty: activeFungalLayerIds.has("fungalAtlasUncertainty"),
    fci: activeFungalLayerIds.has("fungalAtlasFci"),
    samples: activeFungalLayerIds.has("fungalAtlasSamples"),
  };
}

function applyFungalAtlasMapVisibility(map: any, activeFungalLayerIds: Set<string>) {
  if (!map?.getLayer || !map?.setLayoutProperty) return;
  const zoom = Number(map.getZoom?.() ?? 0);
  const visible = fungalEnabledSnapshot(activeFungalLayerIds);
  const setVisible = (id: string, show: boolean) => {
    try {
      if (map.getLayer(id)) map.setLayoutProperty(id, "visibility", show ? "visible" : "none");
    } catch {
      /* map can be changing style while filters update */
    }
  };

  const showCompositeHeat = visible.mycelium || visible.rarity || visible.endemic || visible.fci;
  setVisible("crep-fungal-atlas-composite-raster", showCompositeHeat);
  setVisible("crep-fungal-atlas-mycelium-raster", false);
  // AM/ECM use global SPUN raster tiles; keep each raster tied to its own
  // filter state so toggling one layer does not wake both global tile stacks.
  setVisible("crep-fungal-atlas-am-raster", visible.am);
  setVisible("crep-fungal-atlas-ecm-raster", visible.ecm);
  setVisible("crep-fungal-atlas-rarity-raster", false);
  setVisible("crep-fungal-atlas-endemic-raster", false);
  setVisible("crep-fungal-atlas-fci-raster", false);
  const setCellHeatVisible = (layer: string, show: boolean) => {
    setVisible(`crep-fungal-atlas-cells-${layer}-fill`, show);
    setVisible(`crep-fungal-atlas-cells-${layer}-line`, show);
  };
  setCellHeatVisible("mycelium", visible.mycelium);
  setCellHeatVisible("rarity", visible.rarity);
  setCellHeatVisible("endemic", visible.endemic);
  setCellHeatVisible("fci", visible.fci);
  setCellHeatVisible("protected", visible.protected);
  setCellHeatVisible("uncertainty", visible.uncertainty);
  setVisible("crep-fungal-atlas-protected-fill", visible.protected);
  setVisible("crep-fungal-atlas-protected-line", visible.protected);
  setVisible("crep-fungal-atlas-protected-label", visible.protected && zoom >= 5);
  setVisible("crep-fungal-atlas-uncertainty-fill", visible.uncertainty);
  setVisible("crep-fungal-atlas-uncertainty-line", visible.uncertainty);
  setVisible("crep-fungal-atlas-uncertainty-label", visible.uncertainty && zoom >= 5);
  setVisible("crep-fungal-atlas-samples-dot", visible.samples && zoom >= 9);
  setVisible("crep-fungal-atlas-samples-icon", visible.samples && zoom >= 10);

  try {
    (window as any).__crep_fungal_active_layer_ids = Array.from(activeFungalLayerIds);
    (window as any).__crep_fungal_atlas_enabled = visible;
  } catch {
    /* debug hooks only */
  }

  if (!visible.samples || zoom < 9) {
    try {
      const source = map.getSource?.("crep-fungal-atlas-samples");
      source?.setData?.({ type: "FeatureCollection", features: [] });
    } catch {
      /* sample source may not exist yet */
    }
  }
}

// Event marker component with detailed popup
const EventMarker = memo(function EventMarker({ event, isSelected, isNew, onClick, onDoubleClick, onClose, onFlyTo, onHover }: {
  event: GlobalEvent;
  isSelected: boolean;
  isNew?: boolean;
  onClick: () => void;
  onDoubleClick?: () => void;
  onClose: () => void;
  onFlyTo?: (lat: number, lng: number, zoom?: number) => void;
  onHover?: (event: GlobalEvent | null, point?: HoverPoint) => void;
}) {
  const config = eventTypeConfig[event.type] || eventTypeConfig.default;
  const isCritical = event.severity === "critical" || event.severity === "extreme";
  const isEarthquake = event.type === "earthquake";
  const eventLat = Number(event.lat);
  const eventLng = Number(event.lng);
  const formatNumber = (value: number | undefined, digits = 1) =>
    typeof value === "number" && Number.isFinite(value) ? value.toFixed(digits) : "N/A";

  // Guard against missing coordinates
  if (!Number.isFinite(eventLat) || !Number.isFinite(eventLng)) {
    return null;
  }

  if (typeof window !== "undefined") {
    const debug = ((window as any).__crep_render_debug ||= {
      fungalRenderCalls: 0,
      eventRenderCalls: 0,
    });
    debug.eventRenderCalls += 1;
  }

  // Get event-type-specific data fields
  const getEventSpecificData = () => {
    switch (event.type) {
      case "earthquake":
        return [
          { label: "Magnitude", value: typeof event.magnitude === "number" ? `M${event.magnitude.toFixed(1)}` : "N/A", icon: <Activity className="w-3 h-3" /> },
          { label: "Depth", value: typeof event.depth === "number" ? `${event.depth.toFixed(1)} km` : "N/A", icon: <ArrowDown className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "wildfire":
        return [
          { label: "Area", value: event.magnitude ? `${event.magnitude.toLocaleString()} acres` : "N/A", icon: <Flame className="w-3 h-3" /> },
          { label: "Containment", value: event.containment !== undefined ? `${event.containment}%` : "N/A", icon: <Shield className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "storm":
      case "hurricane":
      case "typhoon":
      case "cyclone":
      case "tornado":
      case "blizzard":
        return [
          { label: "Wind Speed", value: event.magnitude ? `${event.magnitude} mph` : "N/A", icon: <Wind className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "volcano":
        return [
          { label: "Status", value: event.description?.match(/Aviation color code: (\w+)/)?.[1] || "Active", icon: <Mountain className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "solar_flare":
      case "geomagnetic_storm":
        return [
          { label: "Class/Kp", value: event.magnitude ? `Kp ${event.magnitude.toFixed(0)}` : event.title.match(/[MCXAB]\d+\.\d+/)?.[0] || "N/A", icon: <Sun className="w-3 h-3" /> },
          { label: "Effect", value: "Aurora visible at high latitudes", icon: <Sparkles className="w-3 h-3" /> },
        ];
      case "lightning":
        return [
          { label: "Strikes", value: event.magnitude ? `${event.magnitude.toLocaleString()}` : "N/A", icon: <Zap className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "flood":
      case "tsunami":
        return [
          { label: "Status", value: event.type === "tsunami" ? "Active Tsunami Alert" : "Active Flooding", icon: <Droplet className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      case "heatwave":
      case "coldwave":
      case "air_quality":
      case "drought":
      case "landslide":
        return [
          { label: "Status", value: eventTypeConfig[event.type]?.label || "Active Alert", icon: eventTypeConfig[event.type]?.icon || <AlertTriangle className="w-3 h-3" /> },
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
      default:
        return [
          { label: "Location", value: event.locationName || "Unknown", icon: <MapPin className="w-3 h-3" /> },
        ];
    }
  };

  // Get source icon and label
  const getSourceInfo = () => {
    const sourceMap: Record<string, { icon: React.ReactNode; label: string; color: string }> = {
      "USGS": { icon: <Globe className="w-3 h-3" />, label: "USGS Earthquake Hazards", color: "text-amber-400" },
      "NOAA SWPC": { icon: <Sun className="w-3 h-3" />, label: "NOAA Space Weather", color: "text-yellow-400" },
      "NASA EONET": { icon: <Satellite className="w-3 h-3" />, label: "NASA Earth Observatory", color: "text-blue-400" },
      "NHC": { icon: <Cloud className="w-3 h-3" />, label: "National Hurricane Center", color: "text-indigo-400" },
      "NWS": { icon: <Cloud className="w-3 h-3" />, label: "National Weather Service", color: "text-cyan-400" },
      "FIRMS": { icon: <Flame className="w-3 h-3" />, label: "NASA Fire Information", color: "text-orange-400" },
      "Smithsonian GVP": { icon: <Mountain className="w-3 h-3" />, label: "Global Volcanism Program", color: "text-red-400" },
      "Blitzortung": { icon: <Zap className="w-3 h-3" />, label: "Blitzortung Lightning", color: "text-yellow-400" },
      "GDACS": { icon: <AlertTriangle className="w-3 h-3" />, label: "Global Disaster Alert", color: "text-red-400" },
      "MycoBrain Network": { icon: <Radar className="w-3 h-3" />, label: "MycoBrain Sensors", color: "text-green-400" },
      "Movebank": { icon: <Navigation className="w-3 h-3" />, label: "Movebank Animal Tracking", color: "text-emerald-400" },
    };
    return sourceMap[event.source || ""] || { icon: <Database className="w-3 h-3" />, label: event.source || "Unknown Source", color: "text-gray-400" };
  };

  const sourceInfo = getSourceInfo();
  const eventData = getEventSpecificData();
  const mapPreviewUrl = isEarthquake
    ? `/api/search/map-preview?lat=${encodeURIComponent(String(event.lat))}&lng=${encodeURIComponent(String(event.lng))}&mag=${encodeURIComponent(String(event.magnitude ?? 0))}&depth=${encodeURIComponent(String(event.depth ?? ""))}&zoom=8&title=${encodeURIComponent(event.title)}`
    : null;

  return (
    <MapMarker
      longitude={eventLng}
      latitude={eventLat}
      onClick={onClick}
    >
      <MarkerContent
        className="relative cursor-pointer"
        data-marker="event"
        onMouseEnter={(e: React.MouseEvent) => onHover?.(event, { x: e.clientX, y: e.clientY })}
        onMouseMove={(e: React.MouseEvent) => onHover?.(event, { x: e.clientX, y: e.clientY })}
        onMouseLeave={() => onHover?.(null)}
      >
        <div
          role="button"
          tabIndex={0}
          onDoubleClick={(e: React.MouseEvent) => {
            e.stopPropagation();
            onDoubleClick?.();
          }}
          onKeyDown={(e: React.KeyboardEvent) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault();
              e.stopPropagation();
              onDoubleClick?.();
            }
          }}
        >
        <div className={cn(
          // May 21 2026 (Morgan: "events flicker on every zoom"). Dropped
          // `transition-transform` â€” the CSS transition was firing on every
          // re-render of the markers during zoom and made every marker
          // visibly scale, looking like a blink. Plain scale class with no
          // transition is snappier and stable.
          "relative flex items-center justify-center",
          isSelected ? "scale-150" : "scale-100"
        )}>
          {/* Blinking "NEW" ring â€“ event just appeared on map (within viewport) */}
          {isNew && (
            <div
              className="absolute w-7 h-7 rounded-full border-2 border-amber-400/80 pointer-events-none"
              style={{ animationDuration: "1.2s" }}
            />
          )}
          {/* Pulsing ring ONLY for critical events - REDUCED opacity */}
          {isCritical && (
            <div
              className="absolute w-6 h-6 rounded-full pointer-events-none"
              style={{ backgroundColor: `${config.color}20` }}
            />
          )}
          {/* Subtle glow - REDUCED */}
          <div
            className="absolute w-5 h-5 rounded-full blur-[2px]"
            style={{ backgroundColor: `${config.color}25` }}
          />
          <div
            className={cn(
              "relative w-4 h-4 rounded-full border flex items-center justify-center",
              isSelected && "ring-2 ring-white"
            )}
            style={{
              backgroundColor: config.color,
              borderColor: isSelected ? "#fff" : `${config.color}80`,
              boxShadow: isSelected ? `0 0 8px ${config.color}` : `0 0 4px ${config.color}40`
            }}
          >
            <span className="text-[8px] text-white">{config.icon}</span>
          </div>
        </div>
        </div>
      </MarkerContent>

      {/* ENHANCED EVENT POPUP - Much larger with more data */}
      {isSelected && (
        <MarkerPopup
          className={cn(
            "min-w-[320px] max-w-[380px] bg-[#0a1628]/98 backdrop-blur-md shadow-2xl p-0 overflow-hidden",
            "border-2 border-gray-600/40"
          )}
          closeButton
          closeOnClick={false}
          anchor="bottom"
          offset={[0, -12]}
          onClose={onClose}
        >
        {/* Header with severity gradient */}
        <div
          className="px-3 py-2 border-b border-gray-700/50"
          style={{
            background: `linear-gradient(135deg, ${config.color}40 0%, ${config.color}15 100%)`,
          }}
        >
          <div className="flex items-start gap-2">
            <div
              className="w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0"
              style={{ backgroundColor: `${config.color}50` }}
            >
              {config.icon}
            </div>
            <div className="flex-1 min-w-0">
              <h3 className="text-sm font-bold text-white leading-tight">{event.title}</h3>
              <div className="flex items-center gap-2 mt-0.5">
                <span className="text-[10px] text-gray-400 uppercase">{config.label}</span>
            <Badge
              variant="outline"
                  className={cn("text-[8px] px-1.5 py-0", severityColors[event.severity || "medium"])}
            >
                  {(event.severity || "medium").toUpperCase()}
            </Badge>
          </div>
            </div>
          </div>
        </div>

        {isEarthquake && mapPreviewUrl && (
          <div className="border-b border-gray-700/30 bg-black/30">
            <img
              src={mapPreviewUrl}
              alt={`Satellite map preview for ${event.title}`}
              className="h-28 w-full object-cover"
              loading="lazy"
            />
          </div>
        )}

        {isEarthquake && (
          <div className="px-3 py-2 border-b border-gray-700/30">
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-black/45 rounded p-2 border border-amber-500/25">
                <div className="text-[8px] text-gray-400 uppercase">Magnitude</div>
                <div className="text-sm font-bold text-amber-300">
                  {typeof event.magnitude === "number" ? `M${event.magnitude.toFixed(1)}` : "N/A"}
                </div>
              </div>
              <div className="bg-black/45 rounded p-2 border border-amber-500/25">
                <div className="text-[8px] text-gray-400 uppercase">Depth</div>
                <div className="text-sm font-bold text-white">
                  {typeof event.depth === "number" ? `${event.depth.toFixed(1)} km` : "N/A"}
                </div>
              </div>
              <div className="bg-black/45 rounded p-2 border border-gray-700/40">
                <div className="text-[8px] text-gray-400 uppercase">Latitude</div>
                <div className="text-[11px] font-mono text-cyan-300">{formatNumber(event.lat, 5)}</div>
              </div>
              <div className="bg-black/45 rounded p-2 border border-gray-700/40">
                <div className="text-[8px] text-gray-400 uppercase">Longitude</div>
                <div className="text-[11px] font-mono text-cyan-300">{formatNumber(event.lng, 5)}</div>
              </div>
            </div>
            <div className="mt-2 rounded bg-black/35 px-2 py-1.5 text-[10px] text-gray-300">
              <span className="text-gray-500">Location:</span> {event.locationName || event.title}
            </div>
          </div>
        )}

        {/* Description */}
        {event.description && (
          <div className="px-3 py-2 border-b border-gray-700/30">
            <p className="text-[11px] text-gray-300 leading-relaxed line-clamp-3">
              {event.description}
            </p>
            </div>
          )}

        {/* Event-specific data grid */}
        <div className="px-3 py-2 border-b border-gray-700/30">
          <div className="grid grid-cols-3 gap-2">
            {eventData.map((item, idx) => (
              <div key={idx} className="bg-black/40 rounded p-1.5 border border-gray-700/40">
                <div className="flex items-center gap-1 text-[8px] text-gray-500 uppercase mb-0.5">
                  {item.icon}
                  {item.label}
                </div>
                <div className="text-[11px] text-white font-medium truncate">{item.value}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Coordinates - CLICKABLE to fly to location */}
        <div className="px-3 py-2 border-b border-gray-700/30">
          <button
            onClick={(e) => {
              e.stopPropagation();
              onFlyTo?.(event.lat, event.lng, 10);
            }}
            className="w-full flex items-center justify-between p-2 rounded bg-cyan-500/10 hover:bg-cyan-500/20 border border-cyan-500/30 transition-colors group"
          >
            <div className="flex items-center gap-2">
              <MapPin className="w-4 h-4 text-cyan-400" />
              <div className="text-left">
                <div className="text-[9px] text-gray-500 uppercase">Coordinates</div>
                <div className="text-[11px] text-cyan-400 font-mono">
                  {(event.lat ?? 0).toFixed(5)}Ã‚Â°, {(event.lng ?? 0).toFixed(5)}Ã‚Â°
                </div>
              </div>
            </div>
            <div className="flex items-center gap-1 text-[9px] text-cyan-400 group-hover:text-cyan-300">
              <Navigation className="w-3 h-3" />
              <span>FLY TO</span>
            </div>
          </button>
        </div>

        {/* Timestamp */}
        <div className="px-3 py-2 border-b border-gray-700/30 flex items-center justify-between">
          <div className="flex items-center gap-1.5 text-[10px] text-gray-400">
            <Clock className="w-3.5 h-3.5" />
            <span>Detected</span>
          </div>
          <span className="text-[11px] text-white">
            {event.timestamp ? new Date(event.timestamp).toLocaleString("en-US", {
              month: "short",
              day: "numeric",
              hour: "2-digit",
              minute: "2-digit",
              hour12: true
            }) : "Unknown"}
          </span>
        </div>

        {/* Source and Links */}
        <div className="px-3 py-2 space-y-2">
          {/* Source info */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-1.5">
              <span className={cn("flex items-center gap-1 text-[10px]", sourceInfo.color)}>
                {sourceInfo.icon}
                {sourceInfo.label}
              </span>
            </div>
            {event.sourceUrl && (
              <a
                href={event.sourceUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="text-[9px] text-blue-400 hover:text-blue-300 flex items-center gap-1"
                onClick={(e) => e.stopPropagation()}
              >
                Source <ExternalLink className="w-2.5 h-2.5" />
              </a>
            )}
          </div>

          {/* Action buttons */}
          <div className="flex gap-2">
          {event.link && (
            <a
              href={event.link}
              target="_blank"
              rel="noopener noreferrer"
                className="flex-1 flex items-center justify-center gap-1.5 py-1.5 px-3 rounded bg-cyan-600/20 hover:bg-cyan-600/30 border border-cyan-500/40 text-[10px] text-cyan-400 hover:text-cyan-300 transition-colors"
                onClick={(e) => e.stopPropagation()}
              >
                <ExternalLink className="w-3 h-3" />
                View on {event.source || "Source"}
              </a>
            )}
            {event.sourceUrl && !event.link && (
              <a
                href={event.sourceUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="flex-1 flex items-center justify-center gap-1.5 py-1.5 px-3 rounded bg-cyan-600/20 hover:bg-cyan-600/30 border border-cyan-500/40 text-[10px] text-cyan-400 hover:text-cyan-300 transition-colors"
                onClick={(e) => e.stopPropagation()}
              >
                <ExternalLink className="w-3 h-3" />
                Visit {event.source || "Source"}
            </a>
          )}
          </div>
        </div>
      </MarkerPopup>
      )}
    </MapMarker>
  );
});

function EarthquakeEventPopupOverlay({
  map,
  event,
  onClose,
  onFlyTo,
}: {
  map: any;
  event: GlobalEvent | null;
  onClose: () => void;
  onFlyTo: (event: GlobalEvent) => void;
}) {
  const [point, setPoint] = useState<{ x: number; y: number; viewportX: number; viewportY: number } | null>(null);

  useEffect(() => {
    if (!map || !event) {
      setPoint(null);
      return;
    }

    const updatePoint = () => {
      try {
        const p = map.project([event.lng, event.lat]);
        const rect = map.getContainer?.().getBoundingClientRect?.();
        setPoint({
          x: p.x,
          y: p.y,
          viewportX: (rect?.left ?? 0) + p.x,
          viewportY: (rect?.top ?? 0) + p.y,
        });
      } catch {
        setPoint(null);
      }
    };

    updatePoint();
    map.on?.("move", updatePoint);
    map.on?.("zoom", updatePoint);
    map.on?.("resize", updatePoint);

    return () => {
      map.off?.("move", updatePoint);
      map.off?.("zoom", updatePoint);
      map.off?.("resize", updatePoint);
    };
  }, [map, event]);

  if (!event || !point) return null;

  const magnitude = typeof event.magnitude === "number" ? `M${event.magnitude.toFixed(1)}` : "N/A";
  const depth = typeof event.depth === "number" ? `${event.depth.toFixed(1)} km` : "N/A";
  const mapPreviewUrl = `/api/search/map-preview?lat=${encodeURIComponent(String(event.lat))}&lng=${encodeURIComponent(String(event.lng))}&mag=${encodeURIComponent(String(event.magnitude ?? 0))}&depth=${encodeURIComponent(String(event.depth ?? ""))}&zoom=8&title=${encodeURIComponent(event.title)}`;
  const sourceLink = event.sourceUrl || event.link;
  const viewportWidth = typeof window !== "undefined" ? window.innerWidth : 420;
  const viewportHeight = typeof window !== "undefined" ? window.innerHeight : 720;
  const isMobilePopup = viewportWidth < 640;
  const popupWidth = isMobilePopup ? Math.min(320, viewportWidth - 28) : Math.min(380, viewportWidth - 24);
  const sideInset = isMobilePopup ? 14 : 12;
  const left = Math.max(sideInset, Math.min(point.viewportX - popupWidth / 2, viewportWidth - popupWidth - sideInset));
  const top = isMobilePopup
    ? Math.max(92, Math.min(point.viewportY - 196, viewportHeight - 330))
    : Math.max(78, Math.min(point.viewportY - 260, viewportHeight - 440));

  const popup = (
    <div
      className="pointer-events-auto fixed z-[999] max-h-[min(430px,calc(100vh-96px))] overflow-y-auto rounded-xl border border-amber-300/35 bg-[#07111f]/95 text-white shadow-[0_18px_45px_rgba(0,0,0,0.45)] backdrop-blur-xl sm:max-h-[min(430px,calc(100vh-96px))]"
      style={{
        width: popupWidth,
        left,
        top,
      }}
      data-testid="earthquake-map-popup"
      onClick={(e) => e.stopPropagation()}
    >
      <div className="flex items-start justify-between gap-2 border-b border-white/10 bg-amber-500/10 px-2.5 py-2 sm:gap-3 sm:px-3">
        <div className="min-w-0">
          <div className="text-[9px] font-semibold uppercase tracking-[0.18em] text-amber-200 sm:text-[10px]">Earthquake</div>
          <h3 className="mt-0.5 line-clamp-2 text-xs font-bold leading-tight text-white sm:text-sm">{event.title}</h3>
          <p className="mt-0.5 truncate text-[11px] text-white/65">{event.locationName || event.title}</p>
        </div>
        <button
          type="button"
          aria-label="Close earthquake details"
          onClick={onClose}
          className="search-glass-icon-button h-8 w-8 flex-shrink-0"
        >
          <X className="h-4 w-4" />
        </button>
      </div>

      <img
        src={mapPreviewUrl}
        alt={`Satellite map preview for ${event.title}`}
        className="h-20 w-full border-b border-white/10 object-cover sm:h-28"
        loading="lazy"
      />

      <div className="space-y-1.5 p-2.5 sm:space-y-2 sm:p-3">
        <div className="grid grid-cols-2 gap-2">
          <div className="rounded-lg border border-amber-300/20 bg-black/35 px-2 py-1 sm:py-1.5">
            <div className="text-[9px] uppercase text-white/45">Richter scale</div>
            <div className="text-sm font-bold text-amber-200 sm:text-base">{magnitude}</div>
          </div>
          <div className="rounded-lg border border-cyan-300/20 bg-black/35 px-2 py-1 sm:py-1.5">
            <div className="text-[9px] uppercase text-white/45">Depth</div>
            <div className="text-sm font-bold text-cyan-100 sm:text-base">{depth}</div>
          </div>
          <div className="rounded-lg border border-white/10 bg-black/30 px-2 py-1 sm:py-1.5">
            <div className="text-[9px] uppercase text-white/45">Latitude</div>
            <div className="font-mono text-[12px] text-cyan-200">{event.lat.toFixed(5)}</div>
          </div>
          <div className="rounded-lg border border-white/10 bg-black/30 px-2 py-1 sm:py-1.5">
            <div className="text-[9px] uppercase text-white/45">Longitude</div>
            <div className="font-mono text-[12px] text-cyan-200">{event.lng.toFixed(5)}</div>
          </div>
        </div>

        {event.description && (
          <p className="line-clamp-3 rounded-lg border border-white/10 bg-black/25 px-2 py-1.5 text-[11px] leading-snug text-white/75">
            {event.description}
          </p>
        )}

        <div className="flex items-center justify-between gap-2 text-[11px] text-white/65">
          <span>{event.timestamp ? new Date(event.timestamp).toLocaleString() : "Time unavailable"}</span>
          <span className="font-semibold text-amber-200">{event.source || "USGS"}</span>
        </div>

        <div className="flex gap-2">
          <button
            type="button"
            onClick={() => onFlyTo(event)}
            className="flex flex-1 items-center justify-center gap-1.5 rounded-lg border border-cyan-300/25 bg-cyan-400/10 px-2 py-1.5 text-[10px] font-semibold text-cyan-100 hover:bg-cyan-400/20 sm:px-3 sm:py-2 sm:text-[11px]"
          >
            <Crosshair className="h-3.5 w-3.5" />
            Zoom to county
          </button>
          {sourceLink && (
            <a
              href={sourceLink}
              target="_blank"
              rel="noreferrer"
              className="flex flex-1 items-center justify-center gap-1.5 rounded-lg border border-amber-300/25 bg-amber-400/10 px-3 py-2 text-[11px] font-semibold text-amber-100 hover:bg-amber-400/20"
            >
              <ExternalLink className="h-3.5 w-3.5" />
              Source
            </a>
          )}
        </div>
      </div>
    </div>
  );

  return typeof document === "undefined" ? null : createPortal(popup, document.body);
}

// Device marker component - uses device-widget-mapper for type-specific visuals (Feb 12, 2026)
//
// Apr 20, 2026 (Morgan: "the most beautiful highly detailed and profound
// widget with a different and more visually modern floating high tech ui
// is needed for all device widgets this mycobrain gateway is not over our
// home with no gps on it at the moment but this widget is shit make it
// way better mycobrain-sidea-10b41d"). The popup body now mounts the new
// glass-morphism <DeviceWidget> from components/crep/devices/DeviceWidget.tsx
// â€” it explicitly surfaces GPS state (locked / drift / unavailable / manual)
// so it's obvious when a device's pin is approximate, has a richer header
// with status orb + signal-strength bars, sparkline-bearing telemetry
// cards, and styled quick-control buttons. Pulls history from a per-device
// in-memory ring buffer maintained by sensorHistoryRef.
function DeviceMarker({ device, isSelected, onClick, onClose, history, onControl, onHover }: {
  device: Device;
  isSelected: boolean;
  onClick: () => void;
  onClose?: () => void;
  history?: import("@/components/crep/devices/DeviceWidget").SensorHistory;
  onControl?: (peripheral: string, params?: Record<string, any>) => Promise<void>;
  onHover?: (payload: MapAssetHoverPayload | null) => void;
}) {
  const isOnline = isDeviceConnectedLike(device);
  const [controlLoading, setControlLoading] = useState<string | null>(null);
  const hoverPointRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const isFieldMycoBrain = isFieldMycoBrainDevice(device);

  // Get device-specific widget configuration based on device type (Feb 12, 2026)
  const widgetConfig = getDeviceWidgetConfig(device.type);
  const deviceEmoji = getDeviceEmoji(device.type);

  const buildHoverPayload = useCallback((point?: HoverPoint): MapAssetHoverPayload => ({
    type: "mycobrain",
    kind: "MycoBrain device",
    id: device.id,
    name: device.name,
    label: device.name,
    detail: [device.type, device.status].filter(Boolean).join(" / "),
    lat: device.lat,
    lng: device.lng,
    x: point?.x ?? hoverPointRef.current.x,
    y: point?.y ?? hoverPointRef.current.y,
    source: device.registryId || device.port || "Mycosoft",
    properties: {
      id: device.id,
      name: device.name,
      type: device.type,
      status: device.status,
      registryId: device.registryId,
      temperature: device.sensorData?.temperature,
      humidity: device.sensorData?.humidity,
      iaq: device.sensorData?.iaq,
    },
  }), [device]);

  // Control functions for MycoBrain device
  const sendControl = async (peripheral: string, params?: Record<string, any>) => {
    const registryDeviceId = device.registryId || (typeof device.port === "string" && device.port.startsWith("mycobrain-") ? device.port : undefined);
    if (!registryDeviceId && !device.port) return;
    setControlLoading(peripheral);
    try {
      const isLocalCom4 = registryDeviceId === PSATHYRELLA_COM4_REGISTRY_ID ||
        String(device.port || "").toUpperCase() === "COM4";
      const command = earthSimControlToOperatorCommand(peripheral, params);
      const action =
        peripheral === "neopixel" && params?.effect === "rainbow" ? "rainbow" :
        peripheral === "neopixel" && params?.effect === "off" ? "off" :
        peripheral === "buzzer" ? String(params?.action || "beep") :
        typeof params?.cmd === "string" ? "raw" :
        String(params?.effect || peripheral);
      const localControlId = String(device.port || registryDeviceId);
      const response = registryDeviceId && !isLocalCom4 ? await fetchEarthDeviceControl(`/api/devices/network/${encodeURIComponent(registryDeviceId)}/command`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ command, params: params || {}, timeout: 5 }),
      }) : await fetchEarthDeviceControl(`/api/mycobrain/${encodeURIComponent(localControlId)}/control`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ peripheral, action, ...(params || {}) }),
      });
      const result = await response.json();
      if (!response.ok || !earthDeviceControlResultOk(result)) {
        // Short message only - avoid description; Next.js dev overlay intercepts console.error
        toast(earthDeviceControlFailureMessage(response, result, device), { duration: 5000 });
      }
    } catch {
      toast(isFieldMycoBrain
        ? "Command relay timed out. This field device still reports online."
        : "Device command timed out. Check MycoBrain connection.",
        { duration: 5000 });
    } finally {
      setControlLoading(null);
    }
  };

  // Use device-widget-mapper for IAQ quality (Feb 12, 2026)
  const iaqInfo = getIAQQuality(device.sensorData?.iaq);
  return (
    <>
      <MapMarker
        longitude={device.lng}
        latitude={device.lat}
        onClick={onClick}
      >
        <MarkerContent
          data-marker="device"
          data-device-id={device.id}
          className="relative"
          onMouseEnter={(event) => {
            hoverPointRef.current = { x: event.clientX, y: event.clientY };
            onHover?.(buildHoverPayload(hoverPointRef.current));
          }}
          onMouseMove={(event) => {
            hoverPointRef.current = { x: event.clientX, y: event.clientY };
            onHover?.(buildHoverPayload(hoverPointRef.current));
          }}
          onMouseLeave={() => onHover?.(null)}
        >
        <div className={cn(
          // May 21 2026 (Morgan: "events flicker on every zoom"). Dropped
          // `transition-transform` â€” the CSS transition was firing on every
          // re-render of the markers during zoom and made every marker
          // visibly scale, looking like a blink. Plain scale class with no
          // transition is snappier and stable.
          "relative flex items-center justify-center",
          isSelected ? "scale-150" : "scale-100"
        )}>
          {isOnline && (
            <div className={cn(
              isFieldMycoBrain ? "absolute h-9 w-9 rounded-md" : "absolute w-6 h-6 rounded-sm",
              widgetConfig.bgColor.replace("/20", "/30"),
              "motion-safe:animate-ping"
            )} />
          )}
          <div
            className={cn(
              "relative rounded-sm border-2 flex items-center justify-center",
              isFieldMycoBrain ? "h-7 w-7 text-[12px]" : "w-5 h-5 text-[10px]",
              isOnline
                ? cn(widgetConfig.bgColor.replace("/20", "/80"), widgetConfig.borderColor)
                : "bg-red-500/80 border-red-400",
              isSelected && "ring-2 ring-white",
              isOnline && "motion-safe:animate-pulse"
            )}
            style={{ boxShadow: `0 0 ${isFieldMycoBrain ? 16 : 10}px ${isOnline ? widgetConfig.glowColor : "#ef4444"}` }}
          >
            {isFieldMycoBrain ? <Box className="h-4 w-4 text-white" strokeWidth={2.4} /> : deviceEmoji}
          </div>
        </div>
        </MarkerContent>
      </MapMarker>
      {isSelected && (
        <DeviceWidget
          device={device as any}
          history={history}
          onClose={onClose || onClick}
          onControl={onControl || sendControl}
        />
      )}
      {/* Old MarkerPopup body removed â€” replaced by DeviceWidget above. */}
    </>
  );
}

