// Format number helper
function formatNum(num: number): string {
  if (num >= 1e12) return (num / 1e12).toFixed(2) + "T";
  if (num >= 1e9) return (num / 1e9).toFixed(2) + "B";
  if (num >= 1e6) return (num / 1e6).toFixed(1) + "M";
  if (num >= 1e3) return (num / 1e3).toFixed(1) + "K";
  return num.toLocaleString();
}

function OpenGridOrbitMini({
  mapBounds,
  mapZoom,
  projectionMode,
  onNavigate,
}: {
  mapBounds: { north: number; south: number; east: number; west: number } | null;
  mapZoom: number;
  projectionMode: "globe" | "mercator";
  onNavigate?: (lng: number, lat: number, zoom?: number) => void;
}) {
  const lat = mapBounds ? (mapBounds.north + mapBounds.south) / 2 : 0;
  const rawLng = mapBounds ? (mapBounds.east + mapBounds.west) / 2 : 0;
  const lng = rawLng > 180 ? rawLng - 360 : rawLng < -180 ? rawLng + 360 : rawLng;
  const dotX = Math.max(15, Math.min(85, ((lng + 180) / 360) * 100));
  const dotY = Math.max(15, Math.min(85, (1 - ((lat + 90) / 180)) * 100));
  const pickPoint = (event: React.PointerEvent<HTMLButtonElement> | React.MouseEvent<HTMLButtonElement>) => {
    if (!onNavigate) return;
    const rect = event.currentTarget.getBoundingClientRect();
    const x = Math.max(0, Math.min(1, (event.clientX - rect.left) / rect.width));
    const y = Math.max(0, Math.min(1, (event.clientY - rect.top) / rect.height));
    const nextLng = (x * 360) - 180;
    const nextLat = 90 - (y * 180);
    onNavigate(nextLng, Math.max(-82, Math.min(82, nextLat)), Math.max(2, mapZoom));
  };

  return (
    <div className="w-24 rounded-full border border-cyan-400/35 bg-black/55 p-2 shadow-[0_0_24px_rgba(34,211,238,0.3)] backdrop-blur-md">
      <button
        type="button"
        aria-label="Navigate globe"
        title="Click or drag on the mini globe to move the map"
        onClick={pickPoint}
        onPointerDown={(event) => {
          event.currentTarget.setPointerCapture?.(event.pointerId);
          pickPoint(event);
        }}
        onPointerMove={(event) => {
          if (event.buttons === 1) pickPoint(event);
        }}
        className="relative block aspect-square w-full overflow-hidden rounded-full border border-cyan-300/50 bg-gradient-to-br from-slate-950 via-slate-900 to-black focus:outline-none focus:ring-2 focus:ring-cyan-300/70"
      >
        <div className="absolute inset-2 rounded-full border border-cyan-500/15" />
        <div className="absolute inset-0 opacity-55">
          <div className="absolute left-1/2 top-0 h-full w-px bg-cyan-400/20" />
          <div className="absolute top-1/2 left-0 h-px w-full bg-cyan-400/20" />
          <div className="absolute left-[22%] top-0 h-full w-px bg-cyan-400/10 rotate-[18deg]" />
          <div className="absolute right-[22%] top-0 h-full w-px bg-cyan-400/10 -rotate-[18deg]" />
        </div>
        <div className="absolute inset-[17%] rounded-full border border-cyan-300/20 border-dashed" />
        <div
          className="absolute h-2 w-2 -translate-x-1/2 -translate-y-1/2 rounded-full border border-white bg-cyan-300 shadow-[0_0_10px_rgba(103,232,249,0.9)]"
          style={{ left: `${dotX}%`, top: `${dotY}%` }}
        />
      </button>
      <div className="mt-1 text-center font-mono text-[7px] leading-tight text-cyan-200">
        z{mapZoom.toFixed(1)} {projectionMode === "globe" ? "GLOBE" : "MAP"}
      </div>
    </div>
  );
}

const LEGEND_BUTTON_ACTIVE_CLASSES = ["border-green-400/55", "bg-green-500/15", "text-green-100"] as const;
const LEGEND_BUTTON_INACTIVE_CLASSES = ["border-red-500/45", "bg-red-950/25", "text-red-200"] as const;

function setLegendButtonPressed(button: HTMLElement | null, pressed: boolean) {
  if (!button) return;
  button.setAttribute("aria-pressed", pressed ? "true" : "false");
  button.classList.remove(...(pressed ? LEGEND_BUTTON_INACTIVE_CLASSES : LEGEND_BUTTON_ACTIVE_CLASSES));
  button.classList.add(...(pressed ? LEGEND_BUTTON_ACTIVE_CLASSES : LEGEND_BUTTON_INACTIVE_CLASSES));
}

function setExclusiveMycorrhizalButtonPressed(layerId: string | undefined, pressed: boolean) {
  if (typeof document === "undefined") return;
  if (layerId !== "fungalAtlasAM" && layerId !== "fungalAtlasECM") return;
  const amButton = document.querySelector('[data-crep-layer-toggle="fungalAtlasAM"]') as HTMLElement | null;
  const ecmButton = document.querySelector('[data-crep-layer-toggle="fungalAtlasECM"]') as HTMLElement | null;
  if (layerId === "fungalAtlasAM") {
    setLegendButtonPressed(amButton, pressed);
    if (pressed) setLegendButtonPressed(ecmButton, false);
  } else {
    setLegendButtonPressed(ecmButton, pressed);
    if (pressed) setLegendButtonPressed(amButton, false);
  }
}

function LegendFilterButton({
  icon,
  color,
  label,
  active,
  onClick,
  disabled = false,
  title,
  layerId,
  nativeKey,
}: {
  icon: React.ReactNode;
  color: string;
  label: string;
  active: boolean;
  onClick: () => void;
  disabled?: boolean;
  title?: string;
  layerId?: string;
  nativeKey?: string;
}) {
  const lastActivationAtRef = useRef(0);
  const activate = (
    event:
      | React.MouseEvent<HTMLButtonElement>
      | React.PointerEvent<HTMLButtonElement>
      | React.TouchEvent<HTMLButtonElement>
      | React.KeyboardEvent<HTMLButtonElement>,
  ) => {
    if (disabled) return;
    event.preventDefault();
    event.stopPropagation();
    const nextPressed = event.currentTarget.getAttribute("aria-pressed") !== "true";
    if (layerId === "fungalAtlasAM" || layerId === "fungalAtlasECM") {
      setExclusiveMycorrhizalButtonPressed(layerId, nextPressed);
    } else {
      setLegendButtonPressed(event.currentTarget, nextPressed);
    }
    onClick();
  };
  const shouldHandlePointer = (event: React.PointerEvent<HTMLButtonElement>) => {
    if (!event.isPrimary) return false;
    if (event.pointerType === "mouse" && event.button !== 0) return false;
    return true;
  };

  return (
    <button
      type="button"
      aria-pressed={active}
      data-crep-layer-toggle={layerId ?? nativeKey}
      data-crep-native-key={nativeKey}
      disabled={disabled}
      title={title || label}
      onPointerDown={(event) => {
        if (!shouldHandlePointer(event)) return;
        lastActivationAtRef.current = Date.now();
        activate(event);
      }}
      onKeyDown={(event) => {
        if (event.key === "Enter" || event.key === " ") {
          lastActivationAtRef.current = Date.now();
          activate(event);
        }
      }}
      onClick={(event) => {
        if (Date.now() - lastActivationAtRef.current < 350) {
          event.preventDefault();
          return;
        }
        lastActivationAtRef.current = Date.now();
        activate(event);
      }}
      className={cn(
        "flex min-w-0 touch-manipulation select-none items-center gap-1.5 rounded border px-1.5 py-1 text-left transition-[transform,background-color,border-color,color,box-shadow] duration-75 ease-out active:scale-[0.96]",
        active ? LEGEND_BUTTON_ACTIVE_CLASSES.join(" ") : LEGEND_BUTTON_INACTIVE_CLASSES.join(" "),
        disabled && "cursor-not-allowed opacity-50"
      )}
    >
      <span
        className="flex h-4 w-4 shrink-0 items-center justify-center rounded-full text-[10px]"
        style={{ backgroundColor: `${color}2a`, color }}
      >
        {icon}
      </span>
      <span className="min-w-0 truncate text-[8.5px] font-medium">{label}</span>
    </button>
  );
}

