                      "Hydro", "#0ea5e9",
                      "Pumped Storage", "#0284c7",
                      "Nuclear", "#34d399",
                      "Gas", "#a78bfa",
                      "Coal", "#9ca3af",
                      "Oil", "#fb7185",
                      "Storage", "#f472b6",
                      "Battery", "#f472b6",
                      "Geothermal", "#2dd4bf",
