                    if (result.mode !== "pmtiles" && result.mode !== "geojson") return;
                    const spec = layerSpecForMode(result.mode, INFRA_LAYERS.dataCentersGlobal);
                    // Apr 19, 2026 (Morgan: "larger glowing blue squares for
